import type { Article, LawSection } from '../../../common/types/law.types';

export const SECTION_13: LawSection = { id: 'ccyc-s13', lawId: 'codigo-civil-comercial', number: 'XIII', name: 'Libro Tercero - Responsabilidad Civil (Arts. 1721-1881)', articleStart: 1721, articleEnd: 1881, titles: [] };

export const ARTICLES_13: Article[] = [
  { id: 'ccyc-art-1721', lawId: 'codigo-civil-comercial', number: '1721', order: 1721, title: "Factores de atribución", text: "Factores de atribución. La atribución de un daño al responsable puede basarse en factores objetivos o subjetivos. En ausencia de normativa, el factor de atribución es la culpa.", plainLanguageExplanation: "Establece el régimen de factores de atribución. La atribución de un daño al responsable puede basarse en factores objetivos o subjetivos.", practicalEffects: ['En la práctica, este artículo rige factores de atribución. La atribución de un daño al responsable puede basarse en factores objetivos o subjetivos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['factores', 'atribucin', 'articulo 1721'], segments: [], amendments: [] },
  { id: 'ccyc-art-1722', lawId: 'codigo-civil-comercial', number: '1722', order: 1722, title: "Factor objetivo", text: "Factor objetivo. El factor de atribución es objetivo cuando la culpa del agente es irrelevante a los efectos de atribuir responsabilidad. En tales casos, el responsable se libera demos-trando la causa ajena, excepto disposición legal en contrario.", plainLanguageExplanation: "Establece el régimen de factor objetivo. El factor de atribución es objetivo cuando la culpa del agente es irrelevante a los efectos de atribuir responsabilidad.", practicalEffects: ['En la práctica, este artículo rige factor objetivo. El factor de atribución es objetivo cuando la culpa del agente es irrelevante a los efectos de atribuir responsabilidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['factor', 'objetivo', 'articulo 1722'], segments: [], amendments: [] },
  { id: 'ccyc-art-1723', lawId: 'codigo-civil-comercial', number: '1723', order: 1723, title: "Responsabilidad objetiva", text: "Responsabilidad objetiva. Cuando de las circunstancias de la obligación, o de lo convenido por las partes, surge que el deudor debe obtener un resultado determinado, su responsabilidad es objetiva.", plainLanguageExplanation: "Establece el régimen de responsabilidad objetiva. Cuando de las circunstancias de la obligación, o de lo convenido por las partes, surge que el deudor debe obtener un resultado determinado, su responsabilidad es objetiva.", practicalEffects: ['En la práctica, este artículo rige responsabilidad objetiva. Cuando de las circunstancias de la obligación, o de lo convenido por las partes, surge que el deudor debe obtener un resultado determinado, su respons'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'objetiva', 'articulo 1723'], segments: [], amendments: [] },
  { id: 'ccyc-art-1724', lawId: 'codigo-civil-comercial', number: '1724', order: 1724, title: "Factores subjetivos", text: "Factores subjetivos. Son factores subjetivos de atribución la culpa y el dolo. La culpa consiste en la omisión de la diligencia debida según la naturaleza de la obligación y las circunstancias de las personas, el tiempo y el lugar. Comprende la imprudencia, la negligencia y la impericia en el arte o profesión. El dolo se configura por la producción de un daño de manera intencional o con manifiesta indiferencia por los intereses ajenos.", plainLanguageExplanation: "Establece el régimen de factores subjetivos. Son factores subjetivos de atribución la culpa y el dolo.", practicalEffects: ['En la práctica, este artículo rige factores subjetivos. Son factores subjetivos de atribución la culpa y el dolo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['factores', 'subjetivos', 'articulo 1724'], segments: [], amendments: [] },
  { id: 'ccyc-art-1725', lawId: 'codigo-civil-comercial', number: '1725', order: 1725, title: "Valoración de la conducta", text: "Valoración de la conducta. Cuanto mayor sea el deber de obrar con prudencia y pleno conocimiento de las cosas, mayor es la diligencia exigible al agente y la valoración de la previsibilidad de las consecuencias. Cuando existe una confianza especial, se debe tener en cuenta la naturaleza del acto y las condiciones particulares de las partes. Para valorar la conducta no se toma en cuenta la condición especial, o la facultad intelectual de una persona determinada, a no ser en los contratos que suponen una confianza especial entre las partes. En estos casos, se estima el grado de responsabilidad, por la condición especial del agente.", plainLanguageExplanation: "Establece el régimen de valoración de la conducta. Cuanto mayor sea el deber de obrar con prudencia y pleno conocimiento de las cosas, mayor es la diligencia exigible al agente y la valoración de la previsibilidad de las consecuencias.", practicalEffects: ['En la práctica, este artículo rige valoración de la conducta. Cuanto mayor sea el deber de obrar con prudencia y pleno conocimiento de las cosas, mayor es la diligencia exigible al agente y la valoración de la previsibilidad de las consecuencias.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['valoracin', 'conducta', 'articulo 1725'], segments: [], amendments: [] },
  { id: 'ccyc-art-1726', lawId: 'codigo-civil-comercial', number: '1726', order: 1726, title: "Relación causal", text: "Relación causal. Son reparables las consecuencias dañosas que tienen nexo adecuado de causalidad con el hecho productor del daño. Excepto disposición legal en contrario, se indemnizan las consecuencias inmediatas y las mediatas previsibles.", plainLanguageExplanation: "Establece el régimen de relación causal. Son reparables las consecuencias dañosas que tienen nexo adecuado de causalidad con el hecho productor del daño.", practicalEffects: ['En la práctica, este artículo rige relación causal. Son reparables las consecuencias dañosas que tienen nexo adecuado de causalidad con el hecho productor del daño.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['relacin', 'causal', 'articulo 1726'], segments: [], amendments: [] },
  { id: 'ccyc-art-1727', lawId: 'codigo-civil-comercial', number: '1727', order: 1727, title: "Tipos de consecuencias", text: "Tipos de consecuencias. Las consecuencias de un hecho que acostumbran a suceder según el curso natural y ordinario de las cosas, se llaman en este Código 'consecuencias inmediatas'. Las consecuencias que resultan solamente de la conexión de un hecho con un acontecimiento distinto, se llaman 'consecuencias mediatas'. Las consecuencias mediatas que no pueden preverse se llaman 'consecuencias casuales'.", plainLanguageExplanation: "Establece el régimen de tipos de consecuencias. Las consecuencias de un hecho que acostumbran a suceder según el curso natural y ordinario de las cosas, se llaman en este Código 'consecuencias inmediatas'.", practicalEffects: ['En la práctica, este artículo rige tipos de consecuencias. Las consecuencias de un hecho que acostumbran a suceder según el curso natural y ordinario de las cosas, se llaman en este Código \'consecuencias inmediatas\'.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tipos', 'consecuencias', 'articulo 1727'], segments: [], amendments: [] },
  { id: 'ccyc-art-1728', lawId: 'codigo-civil-comercial', number: '1728', order: 1728, title: "Previsibilidad contractual", text: "Previsibilidad contractual. En los contratos se responde por las consecuencias que las partes previeron o pudieron haber previsto al momento de su celebración. Cuando existe dolo del deudor, la responsabilidad se fija tomando en cuenta estas consecuencias también al momento del incumplimiento.", plainLanguageExplanation: "Establece el régimen de previsibilidad contractual. En los contratos se responde por las consecuencias que las partes previeron o pudieron haber previsto al momento de su celebración.", practicalEffects: ['En la práctica, este artículo rige previsibilidad contractual. En los contratos se responde por las consecuencias que las partes previeron o pudieron haber previsto al momento de su celebración.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['previsibilidad', 'contractual', 'articulo 1728'], segments: [], amendments: [] },
  { id: 'ccyc-art-1729', lawId: 'codigo-civil-comercial', number: '1729', order: 1729, title: "Hecho del damnificado", text: "Hecho del damnificado. La responsabilidad puede ser excluida o limitada por la incidencia del hecho del damnificado en la producción del daño, excepto que la ley o el contrato dispongan que debe tratarse de su culpa, de su dolo, o de cualquier otra circunstancia especial.", plainLanguageExplanation: "Establece el régimen de hecho del damnificado. La responsabilidad puede ser excluida o limitada por la incidencia del hecho del damnificado en la producción del daño, excepto que la ley o el contrato dispongan que debe tratarse de su culpa, de su dolo, o de cualquier otra circunstancia especial.", practicalEffects: ['En la práctica, este artículo rige hecho del damnificado. La responsabilidad puede ser excluida o limitada por la incidencia del hecho del damnificado en la producción del daño, excepto que la ley o el contra'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hecho', 'damnificado', 'articulo 1729'], segments: [], amendments: [] },
  { id: 'ccyc-art-1730', lawId: 'codigo-civil-comercial', number: '1730', order: 1730, title: "Caso fortuito", text: "Caso fortuito. Fuerza mayor. Se considera caso fortuito o fuerza mayor al hecho que no ha podido ser previsto o que, habiendo sido previsto, no ha podido ser evitado. El caso fortuito o fuerza mayor exime de responsabilidad, excepto disposición en contrario. Este Código emplea los términos 'caso fortuito' y 'fuerza mayor' como sinónimos.", plainLanguageExplanation: "Establece el régimen de caso fortuito. Fuerza mayor.", practicalEffects: ['En la práctica, este artículo rige caso fortuito. Fuerza mayor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caso', 'fortuito', 'articulo 1730'], segments: [], amendments: [] },
  { id: 'ccyc-art-1731', lawId: 'codigo-civil-comercial', number: '1731', order: 1731, title: "Hecho de un tercero", text: "Hecho de un tercero. Para eximir de responsabilidad, total o parcialmente, el hecho de un tercero por quien no se debe responder debe reunir los caracteres del caso fortuito.", plainLanguageExplanation: "Establece el régimen de hecho de un tercero. Para eximir de responsabilidad, total o parcialmente, el hecho de un tercero por quien no se debe responder debe reunir los caracteres del caso fortuito.", practicalEffects: ['En la práctica, este artículo rige hecho de un tercero. Para eximir de responsabilidad, total o parcialmente, el hecho de un tercero por quien no se debe responder debe reunir los caracteres del caso fortui'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hecho', 'tercero', 'articulo 1731'], segments: [], amendments: [] },
  { id: 'ccyc-art-1732', lawId: 'codigo-civil-comercial', number: '1732', order: 1732, title: "Imposibilidad de cumplimiento", text: "Imposibilidad de cumplimiento. El deudor de una obligación queda eximido del cumplimiento, y no es responsable, si la obligación se ha extinguido por imposibilidad de cumplimiento objetiva y absoluta no imputable al obligado. La existencia de esa imposibilidad debe apreciarse teniendo en cuenta las exigencias de la buena fe y la prohibición del ejercicio abusivo de los derechos.", plainLanguageExplanation: "Establece el régimen de imposibilidad de cumplimiento. El deudor de una obligación queda eximido del cumplimiento, y no es responsable, si la obligación se ha extinguido por imposibilidad de cumplimiento objetiva y absoluta no imputable al obligado.", practicalEffects: ['En la práctica, este artículo rige imposibilidad de cumplimiento. El deudor de una obligación queda eximido del cumplimiento, y no es responsable, si la obligación se ha extinguido por imposibilidad de cumplimiento objetiva y absoluta no imputable al obligado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imposibilidad', 'cumplimiento', 'articulo 1732'], segments: [], amendments: [] },
  { id: 'ccyc-art-1733', lawId: 'codigo-civil-comercial', number: '1733', order: 1733, title: "Responsabilidad por caso fortuito o por imposibilidad de cumplimiento", text: "Responsabilidad por caso fortuito o por imposibilidad de cumplimiento. Aunque ocurra el caso fortuito o la imposibilidad de cumplimiento, el deudor es responsable en los siguientes casos: a) si ha asumido el cumplimiento aunque ocurra un caso fortuito o una imposibilidad; b) si de una disposición legal resulta que no se libera por caso fortuito o por imposibilidad de cumplimiento; c) si está en mora, a no ser que ésta sea indiferente para la producción del caso fortuito o de la imposibilidad de cumplimiento; d) si el caso fortuito o la imposibilidad de cumplimiento sobrevienen por su culpa; e) si el caso fortuito y, en su caso, la imposibilidad de cumplimiento que de él resulta, constituyen una contingencia propia del riesgo de la cosa o la actividad; f) si está obligado a restituir como consecuencia de un hecho ilícito.", plainLanguageExplanation: "Establece el régimen de responsabilidad por caso fortuito o por imposibilidad de cumplimiento. Aunque ocurra el caso fortuito o la imposibilidad de cumplimiento, el deudor es responsable en los siguientes casos: a) si ha asumido el cumplimiento aunque ocurra un caso fortuito o una imposibilidad; b) si de una disposición legal resulta que no se libera por caso fortuito o po", practicalEffects: ['En la práctica, este artículo rige responsabilidad por caso fortuito o por imposibilidad de cumplimiento. Aunque ocurra el caso fortuito o la imposibilidad de cumplimiento, el deudor es responsable en los siguientes casos: a) si ha asumido el cumplimiento'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'caso', 'fortuito', 'imposibilidad', 'cumplimiento', 'articulo 1733'], segments: [], amendments: [] },
  { id: 'ccyc-art-1734', lawId: 'codigo-civil-comercial', number: '1734', order: 1734, title: "Prueba de los factores de atribución y de las eximentes", text: "Prueba de los factores de atribución y de las eximentes. Excepto disposición legal, la carga de la prueba de los factores de atribución y de las circunstancias eximentes corresponde a quien los alega.", plainLanguageExplanation: "Establece el régimen de prueba de los factores de atribución y de las eximentes. Excepto disposición legal, la carga de la prueba de los factores de atribución y de las circunstancias eximentes corresponde a quien los alega.", practicalEffects: ['En la práctica, este artículo rige prueba de los factores de atribución y de las eximentes. Excepto disposición legal, la carga de la prueba de los factores de atribución y de las circunstancias eximentes corresponde a quien los alega.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'factores', 'atribucin', 'eximentes', 'articulo 1734'], segments: [], amendments: [] },
  { id: 'ccyc-art-1735', lawId: 'codigo-civil-comercial', number: '1735', order: 1735, title: "Facultades judiciales", text: "Facultades judiciales. No obstante, el juez puede distribuir la carga de la prueba de la culpa o de haber actuado con la diligencia debida, ponderando cuál de las partes se halla en mejor situación para aportarla. Si el juez lo considera pertinente, durante el proceso debe comunicar a las partes que aplicará este criterio, de modo de permitir a los litigantes ofrecer y producir los elementos de convicción que hagan a su defensa.", plainLanguageExplanation: "Establece el régimen de facultades judiciales. No obstante, el juez puede distribuir la carga de la prueba de la culpa o de haber actuado con la diligencia debida, ponderando cuál de las partes se halla en mejor situación para aportarla.", practicalEffects: ['En la práctica, este artículo rige facultades judiciales. No obstante, el juez puede distribuir la carga de la prueba de la culpa o de haber actuado con la diligencia debida, ponderando cuál de las partes se halla en mejor situación para aportarla.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades', 'judiciales', 'articulo 1735'], segments: [], amendments: [] },
  { id: 'ccyc-art-1736', lawId: 'codigo-civil-comercial', number: '1736', order: 1736, title: "Prueba de la relación de causalidad", text: "Prueba de la relación de causalidad. La carga de la prueba de la relación de causalidad corresponde a quien la alega, excepto que la ley la impute o la presuma. La carga de la prueba de la causa ajena, o de la imposibilidad de cumplimiento, recae sobre quien la invoca. SECCION 4ª Daño resarcible", plainLanguageExplanation: "Establece el régimen de prueba de la relación de causalidad. La carga de la prueba de la relación de causalidad corresponde a quien la alega, excepto que la ley la impute o la presuma.", practicalEffects: ['En la práctica, este artículo rige prueba de la relación de causalidad. La carga de la prueba de la relación de causalidad corresponde a quien la alega, excepto que la ley la impute o la presuma.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'relacin', 'causalidad', 'articulo 1736'], segments: [], amendments: [] },
  { id: 'ccyc-art-1737', lawId: 'codigo-civil-comercial', number: '1737', order: 1737, title: "Concepto de daño", text: "Concepto de daño. Hay daño cuando se lesiona un derecho o un interés no reprobado por el ordenamiento jurídico, que tenga por objeto la persona, el patrimonio, o un derecho de incidencia colectiva.", plainLanguageExplanation: "Establece el régimen de concepto de daño. Hay daño cuando se lesiona un derecho o un interés no reprobado por el ordenamiento jurídico, que tenga por objeto la persona, el patrimonio, o un derecho de incidencia colectiva.", practicalEffects: ['En la práctica, este artículo rige concepto de daño. Hay daño cuando se lesiona un derecho o un interés no reprobado por el ordenamiento jurídico, que tenga por objeto la persona, el patrimonio, o un der'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concepto', 'dao', 'articulo 1737'], segments: [], amendments: [] },
  { id: 'ccyc-art-1738', lawId: 'codigo-civil-comercial', number: '1738', order: 1738, title: "Indemnización", text: "Indemnización. La indemnización comprende la pérdida o disminución del patrimonio de la víctima, el lucro cesante en el beneficio económico esperado de acuerdo a la probabilidad objetiva de su obtención y la pérdida de chances. Incluye especialmente las consecuencias de la violación de los derechos personalísimos de la víctima, de su integridad personal, su salud psicofísica, sus afecciones espirituales legítimas y las que resultan de la interferencia en su proyecto de vida.", plainLanguageExplanation: "Establece el régimen de indemnización. La indemnización comprende la pérdida o disminución del patrimonio de la víctima, el lucro cesante en el beneficio económico esperado de acuerdo a la probabilidad objetiva de su obtención y la pérdida de chances.", practicalEffects: ['En la práctica, este artículo rige indemnización. La indemnización comprende la pérdida o disminución del patrimonio de la víctima, el lucro cesante en el beneficio económico esperado de acuerdo a la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indemnizacinarticulo 1738'], segments: [], amendments: [] },
  { id: 'ccyc-art-1739', lawId: 'codigo-civil-comercial', number: '1739', order: 1739, title: "Requisitos", text: "Requisitos. Para la procedencia de la indemnización debe existir un perjuicio directo o indirecto, actual o futuro, cierto y subsistente. La pérdida de chance es indemnizable en la medida en que su contingencia sea razonable y guarde una adecuada relación de causalidad con el hecho generador.", plainLanguageExplanation: "Establece el régimen de requisitos. Para la procedencia de la indemnización debe existir un perjuicio directo o indirecto, actual o futuro, cierto y subsistente.", practicalEffects: ['En la práctica, este artículo rige requisitos. Para la procedencia de la indemnización debe existir un perjuicio directo o indirecto, actual o futuro, cierto y subsistente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 1739'], segments: [], amendments: [] },
  { id: 'ccyc-art-1740', lawId: 'codigo-civil-comercial', number: '1740', order: 1740, title: "Reparación plena", text: "Reparación plena. La reparación del daño debe ser plena. Consiste en la restitución de la situación del damnificado al estado anterior al hecho dañoso, sea por el pago en dinero o en especie. La víctima puede optar por el reintegro específico, excepto que sea parcial o totalmente imposible, excesivamente oneroso o abusivo, en cuyo caso se debe fijar en dinero. En el caso de daños derivados de la lesión del honor, la intimidad o la identidad personal, el juez puede, a pedido de parte, ordenar la publicación de la sentencia, o de sus partes pertinentes, a costa del responsable.", plainLanguageExplanation: "Establece el régimen de reparación plena. La reparación del daño debe ser plena.", practicalEffects: ['En la práctica, este artículo rige reparación plena. La reparación del daño debe ser plena.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reparacin', 'plena', 'articulo 1740'], segments: [], amendments: [] },
  { id: 'ccyc-art-1741', lawId: 'codigo-civil-comercial', number: '1741', order: 1741, title: "Indemnización de las consecuencias no patrimoniales", text: "Indemnización de las consecuencias no patrimoniales. Está legitimado para reclamar la indemnización de las consecuencias no patrimoniales el damnificado directo. Si del hecho resulta su muerte o sufre gran discapacidad también tienen legitimación a título personal, según las circunstancias, los ascendientes, los descendientes, el cónyuge y quienes convivían con aquél recibiendo trato familiar ostensible. La acción sólo se transmite a los sucesores universales del legitimado si es interpuesta por éste. El monto de la indemnización debe fijarse ponderando las satisfacciones sustitutivas y compensatorias que pueden procurar las sumas reconocidas.", plainLanguageExplanation: "Establece el régimen de indemnización de las consecuencias no patrimoniales. Está legitimado para reclamar la indemnización de las consecuencias no patrimoniales el damnificado directo.", practicalEffects: ['En la práctica, este artículo rige indemnización de las consecuencias no patrimoniales. Está legitimado para reclamar la indemnización de las consecuencias no patrimoniales el damnificado directo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indemnizacin', 'consecuencias', 'patrimoniales', 'articulo 1741'], segments: [], amendments: [] },
  { id: 'ccyc-art-1742', lawId: 'codigo-civil-comercial', number: '1742', order: 1742, title: "Atenuación de la responsabilidad", text: "Atenuación de la responsabilidad. El juez, al fijar la indemnización, puede atenuarla si es equitativo en función del patrimonio del deudor, la situación personal de la víctima y las cir-cunstancias del hecho. Esta facultad no es aplicable en caso de dolo del responsable.", plainLanguageExplanation: "Establece el régimen de atenuación de la responsabilidad. El juez, al fijar la indemnización, puede atenuarla si es equitativo en función del patrimonio del deudor, la situación personal de la víctima y las cir-cunstancias del hecho.", practicalEffects: ['En la práctica, este artículo rige atenuación de la responsabilidad. El juez, al fijar la indemnización, puede atenuarla si es equitativo en función del patrimonio del deudor, la situación personal de la víctima y las cir-cunstancias del hecho.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atenuacin', 'responsabilidad', 'articulo 1742'], segments: [], amendments: [] },
  { id: 'ccyc-art-1743', lawId: 'codigo-civil-comercial', number: '1743', order: 1743, title: "Dispensa anticipada de la responsabilidad", text: "Dispensa anticipada de la responsabilidad. Son inválidas las cláusulas que eximen o limitan la obligación de indemnizar cuando afectan derechos indisponibles, atentan contra la buena fe, las buenas costumbres o leyes imperativas, o son abusivas. Son también inválidas si liberan anticipadamente, en forma total o parcial, del daño sufrido por dolo del deudor o de las personas por las cuales debe responder.", plainLanguageExplanation: "Establece el régimen de dispensa anticipada de la responsabilidad. Son inválidas las cláusulas que eximen o limitan la obligación de indemnizar cuando afectan derechos indisponibles, atentan contra la buena fe, las buenas costumbres o leyes imperativas, o son abusivas.", practicalEffects: ['En la práctica, este artículo rige dispensa anticipada de la responsabilidad. Son inválidas las cláusulas que eximen o limitan la obligación de indemnizar cuando afectan derechos indisponibles, atentan contra la buena fe, las bu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['dispensa', 'anticipada', 'responsabilidad', 'articulo 1743'], segments: [], amendments: [] },
  { id: 'ccyc-art-1744', lawId: 'codigo-civil-comercial', number: '1744', order: 1744, title: "Prueba del daño", text: "Prueba del daño. El daño debe ser acreditado por quien lo invoca, excepto que la ley lo impute o presuma, o que surja notorio de los propios hechos.", plainLanguageExplanation: "Establece el régimen de prueba del daño. El daño debe ser acreditado por quien lo invoca, excepto que la ley lo impute o presuma, o que surja notorio de los propios hechos.", practicalEffects: ['En la práctica, este artículo rige prueba del daño. El daño debe ser acreditado por quien lo invoca, excepto que la ley lo impute o presuma, o que surja notorio de los propios hechos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prueba', 'dao', 'articulo 1744'], segments: [], amendments: [] },
  { id: 'ccyc-art-1745', lawId: 'codigo-civil-comercial', number: '1745', order: 1745, title: "Indemnización por fallecimiento", text: "Indemnización por fallecimiento. En caso de muerte, la indemnización debe consistir en: a) los gastos necesarios para asistencia y posterior funeral de la víctima. El derecho a repetirlos incumbe a quien los paga, aunque sea en razón de una obligación legal; b) lo necesario para alimentos del cónyuge, del conviviente, de los hijos menores de veintiún años de edad con derecho alimentario, de los hijos incapaces o con capacidad restringida, aunque no hayan sido declarados tales judicialmente; esta indemnización procede aun cuando otra persona deba prestar alimentos al damnificado indirecto; el juez, para fijar la reparación, debe tener en cuenta el tiempo probable de vida de la víctima, sus condiciones personales y las de los reclamantes; c) la pérdida de chance de ayuda futura como consecuencia de la muerte de los hijos; este derecho también compete a quien tenga la guarda del menor fallecido.", plainLanguageExplanation: "Establece el régimen de indemnización por fallecimiento. En caso de muerte, la indemnización debe consistir en: a) los gastos necesarios para asistencia y posterior funeral de la víctima.", practicalEffects: ['En la práctica, este artículo rige indemnización por fallecimiento. En caso de muerte, la indemnización debe consistir en: a) los gastos necesarios para asistencia y posterior funeral de la víctima.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indemnizacin', 'fallecimiento', 'articulo 1745'], segments: [], amendments: [] },
  { id: 'ccyc-art-1746', lawId: 'codigo-civil-comercial', number: '1746', order: 1746, title: "Indemnización por lesiones o incapacidad física o psíquica", text: "Indemnización por lesiones o incapacidad física o psíquica. En caso de lesiones o incapacidad permanente, física o psíquica, total o parcial, la indemnización debe ser evaluada mediante la determinación de un capital, de tal modo que sus rentas cubran la disminución de la aptitud del damnificado para realizar actividades productivas o económicamente valorables, y que se agote al término del plazo en que razonablemente pudo continuar realizando tales actividades. Se presumen los gastos médicos, farmacéuticos y por transporte que resultan razonables en función de la índole de las lesiones o la incapacidad. En el supuesto de incapacidad permanente se debe indemnizar el daño aunque el damnificado continúe ejerciendo una tarea remunerada. Esta indemnización procede aun cuando otra persona deba prestar alimentos al damnificado.", plainLanguageExplanation: "Establece el régimen de indemnización por lesiones o incapacidad física o psíquica. En caso de lesiones o incapacidad permanente, física o psíquica, total o parcial, la indemnización debe ser evaluada mediante la determinación de un capital, de tal modo que sus rentas cubran la disminución de la aptitud del damnificado para realizar actividades productivas o eco", practicalEffects: ['En la práctica, este artículo rige indemnización por lesiones o incapacidad física o psíquica. En caso de lesiones o incapacidad permanente, física o psíquica, total o parcial, la indemnización debe ser evaluada mediante la determinación de un c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indemnizacin', 'lesiones', 'incapacidad', 'fsica', 'psquica', 'articulo 1746'], segments: [], amendments: [] },
  { id: 'ccyc-art-1747', lawId: 'codigo-civil-comercial', number: '1747', order: 1747, title: "Acumulabilidad del daño moratorio", text: "Acumulabilidad del daño moratorio. El resarcimiento del daño moratorio es acumulable al del daño compensatorio o al valor de la prestación y, en su caso, a la cláusula penal compensatoria, sin perjuicio de la facultad morigeradora del juez cuando esa acumulación resulte abusiva.", plainLanguageExplanation: "Establece el régimen de acumulabilidad del daño moratorio. El resarcimiento del daño moratorio es acumulable al del daño compensatorio o al valor de la prestación y, en su caso, a la cláusula penal compensatoria, sin perjuicio de la facultad morigeradora del juez cuando esa acumulación resulte abusiva.", practicalEffects: ['En la práctica, este artículo rige acumulabilidad del daño moratorio. El resarcimiento del daño moratorio es acumulable al del daño compensatorio o al valor de la prestación y, en su caso, a la cláusula penal compensator'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acumulabilidad', 'dao', 'moratorio', 'articulo 1747'], segments: [], amendments: [] },
  { id: 'ccyc-art-1748', lawId: 'codigo-civil-comercial', number: '1748', order: 1748, title: "Curso de los intereses", text: "Curso de los intereses. El curso de los intereses comienza desde que se produce cada perjuicio. SECCION 5ª Responsabilidad directa", plainLanguageExplanation: "Establece el régimen de curso de los intereses. El curso de los intereses comienza desde que se produce cada perjuicio.", practicalEffects: ['En la práctica, este artículo rige curso de los intereses. El curso de los intereses comienza desde que se produce cada perjuicio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['curso', 'intereses', 'articulo 1748'], segments: [], amendments: [] },
  { id: 'ccyc-art-1749', lawId: 'codigo-civil-comercial', number: '1749', order: 1749, title: "Sujetos responsables", text: "Sujetos responsables. Es responsable directo quien incumple una obligación u ocasiona un daño injustificado por acción u omisión.", plainLanguageExplanation: "Establece el régimen de sujetos responsables. Es responsable directo quien incumple una obligación u ocasiona un daño injustificado por acción u omisión.", practicalEffects: ['En la práctica, este artículo rige sujetos responsables. Es responsable directo quien incumple una obligación u ocasiona un daño injustificado por acción u omisión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sujetos', 'responsables', 'articulo 1749'], segments: [], amendments: [] },
  { id: 'ccyc-art-1750', lawId: 'codigo-civil-comercial', number: '1750', order: 1750, title: "Daños causados por actos involuntarios", text: "Daños causados por actos involuntarios. El autor de un daño causado por un acto involuntario responde por razones de equidad. Se aplica lo dispuesto en el artículo 1742. El acto realizado por quien sufre fuerza irresistible no genera responsabilidad para su autor, sin perjuicio de la que corresponde a título personal a quien ejerce esa fuerza.", plainLanguageExplanation: "Establece el régimen de daños causados por actos involuntarios. El autor de un daño causado por un acto involuntario responde por razones de equidad.", practicalEffects: ['En la práctica, este artículo rige daños causados por actos involuntarios. El autor de un daño causado por un acto involuntario responde por razones de equidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['daos', 'causados', 'actos', 'involuntarios', 'articulo 1750'], segments: [], amendments: [] },
  { id: 'ccyc-art-1751', lawId: 'codigo-civil-comercial', number: '1751', order: 1751, title: "Pluralidad de responsables", text: "Pluralidad de responsables. Si varias personas participan en la producción del daño que tiene una causa única, se aplican las reglas de las obligaciones solidarias. Si la pluralidad deriva de causas distintas, se aplican las reglas de las obligaciones concurrentes.", plainLanguageExplanation: "Establece el régimen de pluralidad de responsables. Si varias personas participan en la producción del daño que tiene una causa única, se aplican las reglas de las obligaciones solidarias.", practicalEffects: ['En la práctica, este artículo rige pluralidad de responsables. Si varias personas participan en la producción del daño que tiene una causa única, se aplican las reglas de las obligaciones solidarias.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'responsables', 'articulo 1751'], segments: [], amendments: [] },
  { id: 'ccyc-art-1752', lawId: 'codigo-civil-comercial', number: '1752', order: 1752, title: "Encubrimiento", text: "Encubrimiento. El encubridor responde en cuanto su cooperación ha causado daño. SECCION 6ª Responsabilidad por el hecho de terceros", plainLanguageExplanation: "Establece el régimen de encubrimiento. El encubridor responde en cuanto su cooperación ha causado daño.", practicalEffects: ['En la práctica, este artículo rige encubrimiento. El encubridor responde en cuanto su cooperación ha causado daño.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['encubrimientoarticulo 1752'], segments: [], amendments: [] },
  { id: 'ccyc-art-1753', lawId: 'codigo-civil-comercial', number: '1753', order: 1753, title: "Responsabilidad del principal por el hecho del dependiente", text: "Responsabilidad del principal por el hecho del dependiente. El principal responde objetivamente por los daños que causen los que están bajo su dependencia, o las personas de las cuales se sirve para el cumplimiento de sus obligaciones, cuando el hecho dañoso acaece en ejercicio o con ocasión de las funciones encomendadas. La falta de discernimiento del dependiente no excusa al principal. La responsabilidad del principal es concurrente con la del dependiente.", plainLanguageExplanation: "Establece el régimen de responsabilidad del principal por el hecho del dependiente. El principal responde objetivamente por los daños que causen los que están bajo su dependencia, o las personas de las cuales se sirve para el cumplimiento de sus obligaciones, cuando el hecho dañoso acaece en ejercicio o con ocasión de las funciones encomendadas.", practicalEffects: ['En la práctica, este artículo rige responsabilidad del principal por el hecho del dependiente. El principal responde objetivamente por los daños que causen los que están bajo su dependencia, o las personas de las cuales se sirve para el cumplimi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'principal', 'hecho', 'dependiente', 'articulo 1753'], segments: [], amendments: [] },
  { id: 'ccyc-art-1754', lawId: 'codigo-civil-comercial', number: '1754', order: 1754, title: "Hecho de los hijos", text: "Hecho de los hijos. Los padres son solidariamente responsables por los daños causados por los hijos que se encuentran bajo su responsabilidad parental y que habitan con ellos, sin perjuicio de la responsabilidad personal y concurrente que pueda caber a los hijos.", plainLanguageExplanation: "Establece el régimen de hecho de los hijos. Los padres son solidariamente responsables por los daños causados por los hijos que se encuentran bajo su responsabilidad parental y que habitan con ellos, sin perjuicio de la responsabilidad personal y concurrente que pueda caber a los hijos.", practicalEffects: ['En la práctica, este artículo rige hecho de los hijos. Los padres son solidariamente responsables por los daños causados por los hijos que se encuentran bajo su responsabilidad parental y que habitan con e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hecho', 'hijos', 'articulo 1754'], segments: [], amendments: [] },
  { id: 'ccyc-art-1755', lawId: 'codigo-civil-comercial', number: '1755', order: 1755, title: "Cesación de la responsabilidad paterna", text: "Cesación de la responsabilidad paterna. La responsabilidad de los padres es objetiva, y cesa si el hijo menor de edad es puesto bajo la vigilancia de otra persona, transitoria o permanentemente. No cesa en el supuesto previsto en el artículo 643. Los padres no se liberan, aunque el hijo menor de edad no conviva con ellos, si esta circunstancia deriva de una causa que les es atribuible. Los padres no responden por los daños causados por sus hijos en tareas inherentes al ejercicio de su profesión o de funciones subordinadas encomendadas por terceros. Tampoco responden por el incumplimiento de obligaciones contractuales válidamente contraídas por sus hijos.", plainLanguageExplanation: "Establece el régimen de cesación de la responsabilidad paterna. La responsabilidad de los padres es objetiva, y cesa si el hijo menor de edad es puesto bajo la vigilancia de otra persona, transitoria o permanentemente.", practicalEffects: ['En la práctica, este artículo rige cesación de la responsabilidad paterna. La responsabilidad de los padres es objetiva, y cesa si el hijo menor de edad es puesto bajo la vigilancia de otra persona, transitoria o permanentemente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cesacin', 'responsabilidad', 'paterna', 'articulo 1755'], segments: [], amendments: [] },
  { id: 'ccyc-art-1756', lawId: 'codigo-civil-comercial', number: '1756', order: 1756, title: "Otras personas encargadas", text: "Otras personas encargadas. Los delegados en el ejercicio de la responsabilidad parental, los tutores y los curadores son responsables como los padres por el daño causado por quienes están a su cargo. Sin embargo, se liberan si acreditan que les ha sido imposible evitar el daño; tal imposibilidad no resulta de la mera circunstancia de haber sucedido el hecho fuera de su presencia. El establecimiento que tiene a su cargo personas internadas responde por la negligencia en el cuidado de quienes, transitoria o permanentemente, han sido puestas bajo su vigilancia y control. SECCION 7ª Responsabilidad derivada de la intervención de cosas y de ciertas actividades", plainLanguageExplanation: "Establece el régimen de otras personas encargadas. Los delegados en el ejercicio de la responsabilidad parental, los tutores y los curadores son responsables como los padres por el daño causado por quienes están a su cargo.", practicalEffects: ['En la práctica, este artículo rige otras personas encargadas. Los delegados en el ejercicio de la responsabilidad parental, los tutores y los curadores son responsables como los padres por el daño causado por quienes están a su cargo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otras', 'personas', 'encargadas', 'articulo 1756'], segments: [], amendments: [] },
  { id: 'ccyc-art-1757', lawId: 'codigo-civil-comercial', number: '1757', order: 1757, title: "Hecho de las cosas y actividades riesgosas", text: "Hecho de las cosas y actividades riesgosas. Toda persona responde por el daño causado por el riesgo o vicio de las cosas, o de las actividades que sean riesgosas o peligrosas por su naturaleza, por los medios empleados o por las circunstancias de su realización. La responsabilidad es objetiva. No son eximentes la autorización administrativa para el uso de la cosa o la realización de la actividad, ni el cumplimiento de las técnicas de prevención.", plainLanguageExplanation: "Establece el régimen de hecho de las cosas y actividades riesgosas. Toda persona responde por el daño causado por el riesgo o vicio de las cosas, o de las actividades que sean riesgosas o peligrosas por su naturaleza, por los medios empleados o por las circunstancias de su realización.", practicalEffects: ['En la práctica, este artículo rige hecho de las cosas y actividades riesgosas. Toda persona responde por el daño causado por el riesgo o vicio de las cosas, o de las actividades que sean riesgosas o peligrosas por su naturaleza,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hecho', 'cosas', 'actividades', 'riesgosas', 'articulo 1757'], segments: [], amendments: [] },
  { id: 'ccyc-art-1758', lawId: 'codigo-civil-comercial', number: '1758', order: 1758, title: "Sujetos responsables", text: "Sujetos responsables. El dueño y el guardián son responsables concurrentes del daño causado por las cosas. Se considera guardián a quien ejerce, por sí o por terceros, el uso, la dirección y el control de la cosa, o a quien obtiene un provecho de ella. El dueño y el guardián no responden si prueban que la cosa fue usada en contra de su voluntad expresa o presunta. En caso de actividad riesgosa o peligrosa responde quien la realiza, se sirve u obtiene provecho de ella, por sí o por terceros, excepto lo dispuesto por la legislación especial.", plainLanguageExplanation: "Establece el régimen de sujetos responsables. El dueño y el guardián son responsables concurrentes del daño causado por las cosas.", practicalEffects: ['En la práctica, este artículo rige sujetos responsables. El dueño y el guardián son responsables concurrentes del daño causado por las cosas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sujetos', 'responsables', 'articulo 1758'], segments: [], amendments: [] },
  { id: 'ccyc-art-1759', lawId: 'codigo-civil-comercial', number: '1759', order: 1759, title: "Daño causado por animales", text: "Daño causado por animales. El daño causado por animales, cualquiera sea su especie, queda comprendido en el artículo 1757. SECCION 8ª Responsabilidad colectiva y anónima", plainLanguageExplanation: "Establece el régimen de daño causado por animales. El daño causado por animales, cualquiera sea su especie, queda comprendido en el artículo 1757.", practicalEffects: ['En la práctica, este artículo rige daño causado por animales. El daño causado por animales, cualquiera sea su especie, queda comprendido en el artículo 1757.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['dao', 'causado', 'animales', 'articulo 1759'], segments: [], amendments: [] },
  { id: 'ccyc-art-1760', lawId: 'codigo-civil-comercial', number: '1760', order: 1760, title: "Cosa suspendida o arrojada", text: "Cosa suspendida o arrojada. Si de una parte de un edificio cae una cosa, o si ésta es arrojada, los dueños y ocupantes de dicha parte responden solidariamente por el daño que cause. Sólo se libera quien demuestre que no participó en su producción.", plainLanguageExplanation: "Establece el régimen de cosa suspendida o arrojada. Si de una parte de un edificio cae una cosa, o si ésta es arrojada, los dueños y ocupantes de dicha parte responden solidariamente por el daño que cause.", practicalEffects: ['En la práctica, este artículo rige cosa suspendida o arrojada. Si de una parte de un edificio cae una cosa, o si ésta es arrojada, los dueños y ocupantes de dicha parte responden solidariamente por el daño que cause.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cosa', 'suspendida', 'arrojada', 'articulo 1760'], segments: [], amendments: [] },
  { id: 'ccyc-art-1761', lawId: 'codigo-civil-comercial', number: '1761', order: 1761, title: "Autor anónimo", text: "Autor anónimo. Si el daño proviene de un miembro no identificado de un grupo determinado responden solidariamente todos sus integrantes, excepto aquel que demuestre que no ha contribuido a su producción.", plainLanguageExplanation: "Establece el régimen de autor anónimo. Si el daño proviene de un miembro no identificado de un grupo determinado responden solidariamente todos sus integrantes, excepto aquel que demuestre que no ha contribuido a su producción.", practicalEffects: ['En la práctica, este artículo rige autor anónimo. Si el daño proviene de un miembro no identificado de un grupo determinado responden solidariamente todos sus integrantes, excepto aquel que demuestre'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['autor', 'annimo', 'articulo 1761'], segments: [], amendments: [] },
  { id: 'ccyc-art-1762', lawId: 'codigo-civil-comercial', number: '1762', order: 1762, title: "Actividad peligrosa de un grupo", text: "Actividad peligrosa de un grupo. Si un grupo realiza una actividad peligrosa para terceros, todos sus integrantes responden solidariamente por el daño causado por uno o más de sus miembros. Sólo se libera quien demuestra que no integraba el grupo. SECCION 9ª Supuestos especiales de responsabilidad", plainLanguageExplanation: "Establece el régimen de actividad peligrosa de un grupo. Si un grupo realiza una actividad peligrosa para terceros, todos sus integrantes responden solidariamente por el daño causado por uno o más de sus miembros.", practicalEffects: ['En la práctica, este artículo rige actividad peligrosa de un grupo. Si un grupo realiza una actividad peligrosa para terceros, todos sus integrantes responden solidariamente por el daño causado por uno o más de sus miembros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actividad', 'peligrosa', 'grupo', 'articulo 1762'], segments: [], amendments: [] },
  { id: 'ccyc-art-1763', lawId: 'codigo-civil-comercial', number: '1763', order: 1763, title: "Responsabilidad de la persona jurídica", text: "Responsabilidad de la persona jurídica. La persona jurídica responde por los daños que causen quienes las dirigen o administran en ejercicio o con ocasión de sus funciones.", plainLanguageExplanation: "Establece el régimen de responsabilidad de la persona jurídica. La persona jurídica responde por los daños que causen quienes las dirigen o administran en ejercicio o con ocasión de sus funciones.", practicalEffects: ['En la práctica, este artículo rige responsabilidad de la persona jurídica. La persona jurídica responde por los daños que causen quienes las dirigen o administran en ejercicio o con ocasión de sus funciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'persona', 'jurdica', 'articulo 1763'], segments: [], amendments: [] },
  { id: 'ccyc-art-1764', lawId: 'codigo-civil-comercial', number: '1764', order: 1764, title: "Inaplicabilidad de normas", text: "Inaplicabilidad de normas. Las disposiciones del Capítulo 1 de este Título no son aplicables a la responsabilidad del Estado de manera directa ni subsidiaria.", plainLanguageExplanation: "Establece el régimen de inaplicabilidad de normas. Las disposiciones del Capítulo 1 de este Título no son aplicables a la responsabilidad del Estado de manera directa ni subsidiaria.", practicalEffects: ['En la práctica, este artículo rige inaplicabilidad de normas. Las disposiciones del Capítulo 1 de este Título no son aplicables a la responsabilidad del Estado de manera directa ni subsidiaria.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inaplicabilidad', 'normas', 'articulo 1764'], segments: [], amendments: [] },
  { id: 'ccyc-art-1765', lawId: 'codigo-civil-comercial', number: '1765', order: 1765, title: "Responsabilidad del Estado", text: "Responsabilidad del Estado. La responsabilidad del Estado se rige por las normas y principios del derecho administrativo nacional o local según corresponda.", plainLanguageExplanation: "Establece el régimen de responsabilidad del estado. La responsabilidad del Estado se rige por las normas y principios del derecho administrativo nacional o local según corresponda.", practicalEffects: ['En la práctica, este artículo rige responsabilidad del estado. La responsabilidad del Estado se rige por las normas y principios del derecho administrativo nacional o local según corresponda.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'estado', 'articulo 1765'], segments: [], amendments: [] },
  { id: 'ccyc-art-1766', lawId: 'codigo-civil-comercial', number: '1766', order: 1766, title: "Responsabilidad del funcionario y del empleado público", text: "Responsabilidad del funcionario y del empleado público. Los hechos y las omisiones de los funcionarios públicos en el ejercicio de sus funciones por no cumplir sino de una manera irregular las obligaciones legales que les están impuestas se rigen por las normas y principios del derecho administrativo nacional o local, según corresponda.", plainLanguageExplanation: "Establece el régimen de responsabilidad del funcionario y del empleado público. Los hechos y las omisiones de los funcionarios públicos en el ejercicio de sus funciones por no cumplir sino de una manera irregular las obligaciones legales que les están impuestas se rigen por las normas y principios del derecho administrativo nacional o local, según correspond", practicalEffects: ['En la práctica, este artículo rige responsabilidad del funcionario y del empleado público. Los hechos y las omisiones de los funcionarios públicos en el ejercicio de sus funciones por no cumplir sino de una manera irregular las obligaciones'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'funcionario', 'empleado', 'pblico', 'articulo 1766'], segments: [], amendments: [] },
  { id: 'ccyc-art-1767', lawId: 'codigo-civil-comercial', number: '1767', order: 1767, title: "Responsabilidad de los establecimientos educativos", text: "Responsabilidad de los establecimientos educativos. El titular de un establecimiento educativo responde por el daño causado o sufrido por sus alumnos menores de edad cuando se hallen o deban hallarse bajo el control de la autoridad escolar. La responsabilidad es objetiva y se exime sólo con la prueba del caso fortuito. El establecimiento educativo debe contratar un seguro de responsabilidad civil, de acuerdo a los requisitos que fije la autoridad en materia aseguradora. Esta norma no se aplica a los establecimientos de educación superior o universitaria.", plainLanguageExplanation: "Establece el régimen de responsabilidad de los establecimientos educativos. El titular de un establecimiento educativo responde por el daño causado o sufrido por sus alumnos menores de edad cuando se hallen o deban hallarse bajo el control de la autoridad escolar.", practicalEffects: ['En la práctica, este artículo rige responsabilidad de los establecimientos educativos. El titular de un establecimiento educativo responde por el daño causado o sufrido por sus alumnos menores de edad cuando se hallen o deban hallarse bajo el control de la autoridad escolar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'establecimientos', 'educativos', 'articulo 1767'], segments: [], amendments: [] },
  { id: 'ccyc-art-1768', lawId: 'codigo-civil-comercial', number: '1768', order: 1768, title: "Profesionales liberales", text: "Profesionales liberales. La actividad del profesional liberal está sujeta a las reglas de las obligaciones de hacer. La responsabilidad es subjetiva, excepto que se haya comprometido un resultado concreto. Cuando la obligación de hacer se preste con cosas, la responsabilidad no está comprendida en la Sección 7a, de este Capítulo, excepto que causen un daño derivado de su vicio. La actividad del profesional liberal no está comprendida en la responsabilidad por actividades riesgosas previstas en el artículo 1757.", plainLanguageExplanation: "Establece el régimen de profesionales liberales. La actividad del profesional liberal está sujeta a las reglas de las obligaciones de hacer.", practicalEffects: ['En la práctica, este artículo rige profesionales liberales. La actividad del profesional liberal está sujeta a las reglas de las obligaciones de hacer.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['profesionales', 'liberales', 'articulo 1768'], segments: [], amendments: [] },
  { id: 'ccyc-art-1769', lawId: 'codigo-civil-comercial', number: '1769', order: 1769, title: "Accidentes de tránsito", text: "Accidentes de tránsito. Los artículos referidos a la responsabilidad derivada de la intervención de cosas se aplican a los daños causados por la circulación de vehículos.", plainLanguageExplanation: "Establece el régimen de accidentes de tránsito. Los artículos referidos a la responsabilidad derivada de la intervención de cosas se aplican a los daños causados por la circulación de vehículos.", practicalEffects: ['En la práctica, este artículo rige accidentes de tránsito. Los artículos referidos a la responsabilidad derivada de la intervención de cosas se aplican a los daños causados por la circulación de vehículos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accidentes', 'trnsito', 'articulo 1769'], segments: [], amendments: [] },
  { id: 'ccyc-art-1770', lawId: 'codigo-civil-comercial', number: '1770', order: 1770, title: "Protección de la vida privada", text: "Protección de la vida privada. El que arbitrariamente se entromete en la vida ajena y publica retratos, difunde correspondencia, mortifica a otros en sus costumbres o sentimientos, o perturba de cualquier modo su intimidad, debe ser obligado a cesar en tales actividades, si antes no cesaron, y a pagar una indemnización que debe fijar el juez, de acuerdo con las circunstancias. Además, a pedido del agraviado, puede ordenarse la publicación de la sentencia en un diario o periódico del lugar, si esta medida es procedente para una adecuada reparación.", plainLanguageExplanation: "Establece el régimen de protección de la vida privada. El que arbitrariamente se entromete en la vida ajena y publica retratos, difunde correspondencia, mortifica a otros en sus costumbres o sentimientos, o perturba de cualquier modo su intimidad, debe ser obligado a cesar en tales actividades, si antes no cesaron, y a pagar una inde", practicalEffects: ['En la práctica, este artículo rige protección de la vida privada. El que arbitrariamente se entromete en la vida ajena y publica retratos, difunde correspondencia, mortifica a otros en sus costumbres o sentimientos,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['proteccin', 'vida', 'privada', 'articulo 1770'], segments: [], amendments: [] },
  { id: 'ccyc-art-1771', lawId: 'codigo-civil-comercial', number: '1771', order: 1771, title: "Acusación calumniosa", text: "Acusación calumniosa. En los daños causados por una acusación calumniosa sólo se responde por dolo o culpa grave. El denunciante o querellante responde por los daños derivados de la falsedad de la denuncia o de la querella si se prueba que no tenía razones justificables para creer que el damnificado estaba implicado. SECCION 10ª Ejercicio de las acciones de responsabilidad", plainLanguageExplanation: "Establece el régimen de acusación calumniosa. En los daños causados por una acusación calumniosa sólo se responde por dolo o culpa grave.", practicalEffects: ['En la práctica, este artículo rige acusación calumniosa. En los daños causados por una acusación calumniosa sólo se responde por dolo o culpa grave.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acusacin', 'calumniosa', 'articulo 1771'], segments: [], amendments: [] },
  { id: 'ccyc-art-1772', lawId: 'codigo-civil-comercial', number: '1772', order: 1772, title: "Daños causados a cosas o bienes", text: "Daños causados a cosas o bienes. Sujetos legitimados. La reparación del menoscabo a un bien o a una cosa puede ser reclamado por: a) el titular de un derecho real sobre la cosa o bien; b) el tenedor y el poseedor de buena fe de la cosa o bien.", plainLanguageExplanation: "Establece el régimen de daños causados a cosas o bienes. Sujetos legitimados.", practicalEffects: ['En la práctica, este artículo rige daños causados a cosas o bienes. Sujetos legitimados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['daos', 'causados', 'cosas', 'bienes', 'articulo 1772'], segments: [], amendments: [] },
  { id: 'ccyc-art-1773', lawId: 'codigo-civil-comercial', number: '1773', order: 1773, title: "Acción contra el responsable directo e indirecto", text: "Acción contra el responsable directo e indirecto. El legitimado tiene derecho a interponer su acción, conjunta o separadamente, contra el responsable directo y el indirecto. SECCION 11ª Acciones civil y penal", plainLanguageExplanation: "Establece el régimen de acción contra el responsable directo e indirecto. El legitimado tiene derecho a interponer su acción, conjunta o separadamente, contra el responsable directo y el indirecto.", practicalEffects: ['En la práctica, este artículo rige acción contra el responsable directo e indirecto. El legitimado tiene derecho a interponer su acción, conjunta o separadamente, contra el responsable directo y el indirecto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'contra', 'responsable', 'directo', 'indirecto', 'articulo 1773'], segments: [], amendments: [] },
  { id: 'ccyc-art-1774', lawId: 'codigo-civil-comercial', number: '1774', order: 1774, title: "Independencia", text: "Independencia. La acción civil y la acción penal resultantes del mismo hecho pueden ser ejercidas independientemente. En los casos en que el hecho dañoso configure al mismo tiempo un delito del derecho criminal, la acción civil puede interponerse ante los jueces penales, conforme a las disposiciones de los códigos procesales o las leyes especiales.", plainLanguageExplanation: "Establece el régimen de independencia. La acción civil y la acción penal resultantes del mismo hecho pueden ser ejercidas independientemente.", practicalEffects: ['En la práctica, este artículo rige independencia. La acción civil y la acción penal resultantes del mismo hecho pueden ser ejercidas independientemente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['independenciaarticulo 1774'], segments: [], amendments: [] },
  { id: 'ccyc-art-1775', lawId: 'codigo-civil-comercial', number: '1775', order: 1775, title: "Suspensión del dictado de la sentencia civil", text: "Suspensión del dictado de la sentencia civil. Si la acción penal precede a la acción civil, o es intentada durante su curso, el dictado de la sentencia definitiva debe suspenderse en el proceso civil hasta la conclusión del proceso penal, con excepción de los siguientes casos: a) si median causas de extinción de la acción penal; b) si la dilación del procedimiento penal provoca, en los hechos, una frustración efectiva del derecho a ser indemnizado; c) si la acción civil por reparación del daño está fundada en un factor objetivo de responsabilidad.", plainLanguageExplanation: "Establece el régimen de suspensión del dictado de la sentencia civil. Si la acción penal precede a la acción civil, o es intentada durante su curso, el dictado de la sentencia definitiva debe suspenderse en el proceso civil hasta la conclusión del proceso penal, con excepción de los siguientes casos: a) si median causas de extinción de la acción pe", practicalEffects: ['En la práctica, este artículo rige suspensión del dictado de la sentencia civil. Si la acción penal precede a la acción civil, o es intentada durante su curso, el dictado de la sentencia definitiva debe suspenderse en el proceso ci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensin', 'dictado', 'sentencia', 'civil', 'articulo 1775'], segments: [], amendments: [] },
  { id: 'ccyc-art-1776', lawId: 'codigo-civil-comercial', number: '1776', order: 1776, title: "Condena penal", text: "Condena penal. La sentencia penal condenatoria produce efectos de cosa juzgada en el proceso civil respecto de la existencia del hecho principal que constituye el delito y de la culpa del condenado.", plainLanguageExplanation: "Establece el régimen de condena penal. La sentencia penal condenatoria produce efectos de cosa juzgada en el proceso civil respecto de la existencia del hecho principal que constituye el delito y de la culpa del condenado.", practicalEffects: ['En la práctica, este artículo rige condena penal. La sentencia penal condenatoria produce efectos de cosa juzgada en el proceso civil respecto de la existencia del hecho principal que constituye el de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condena', 'penal', 'articulo 1776'], segments: [], amendments: [] },
  { id: 'ccyc-art-1777', lawId: 'codigo-civil-comercial', number: '1777', order: 1777, title: "Inexistencia del hecho, de autoría, de delito o de responsabilidad penal", text: "Inexistencia del hecho, de autoría, de delito o de responsabilidad penal. Si la sentencia penal decide que el hecho no existió o que el sindicado como responsable no participó, estas circunstancias no pueden ser discutidas en el proceso civil. Si la sentencia penal decide que un hecho no constituye delito penal o que no compromete la responsabilidad penal del agente, en el proceso civil puede discutirse libremente ese mismo hecho en cuanto generador de responsabilidad civil.", plainLanguageExplanation: "Establece el régimen de inexistencia del hecho, de autoría, de delito o de responsabilidad penal. Si la sentencia penal decide que el hecho no existió o que el sindicado como responsable no participó, estas circunstancias no pueden ser discutidas en el proceso civil.", practicalEffects: ['En la práctica, este artículo rige inexistencia del hecho, de autoría, de delito o de responsabilidad penal. Si la sentencia penal decide que el hecho no existió o que el sindicado como responsable no participó, estas circunstancias no pueden ser discutidas en el proceso civil.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inexistencia', 'hecho', 'autora', 'delito', 'responsabilidad', 'penal', 'articulo 1777'], segments: [], amendments: [] },
  { id: 'ccyc-art-1778', lawId: 'codigo-civil-comercial', number: '1778', order: 1778, title: "Excusas absolutorias", text: "Excusas absolutorias. Las excusas absolutorias penales no afectan a la acción civil, excepto disposición legal expresa en contrario.", plainLanguageExplanation: "Establece el régimen de excusas absolutorias. Las excusas absolutorias penales no afectan a la acción civil, excepto disposición legal expresa en contrario.", practicalEffects: ['En la práctica, este artículo rige excusas absolutorias. Las excusas absolutorias penales no afectan a la acción civil, excepto disposición legal expresa en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['excusas', 'absolutorias', 'articulo 1778'], segments: [], amendments: [] },
  { id: 'ccyc-art-1779', lawId: 'codigo-civil-comercial', number: '1779', order: 1779, title: "Impedimento de reparación del daño", text: "Impedimento de reparación del daño. Impiden la reparación del daño: a) la prueba de la verdad del hecho reputado calumnioso; b) en los delitos contra la vida, haber sido coautor o cómplice, o no haber impedido el hecho pudiendo hacerlo.", plainLanguageExplanation: "Establece el régimen de impedimento de reparación del daño. Impiden la reparación del daño: a) la prueba de la verdad del hecho reputado calumnioso; b) en los delitos contra la vida, haber sido coautor o cómplice, o no haber impedido el hecho pudiendo hacerlo.", practicalEffects: ['En la práctica, este artículo rige impedimento de reparación del daño. Impiden la reparación del daño: a) la prueba de la verdad del hecho reputado calumnioso; b) en los delitos contra la vida, haber sido coautor o cómpli'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impedimento', 'reparacin', 'dao', 'articulo 1779'], segments: [], amendments: [] },
  { id: 'ccyc-art-1780', lawId: 'codigo-civil-comercial', number: '1780', order: 1780, title: "Sentencia penal posterior", text: "Sentencia penal posterior. La sentencia penal posterior a la sentencia civil no produce ningún efecto sobre ella, excepto en el caso de revisión. La revisión procede exclusivamente, y a petición de parte interesada, en los siguientes supuestos: a) si la sentencia civil asigna alcances de cosa juzgada a cuestiones resueltas por la sentencia penal y ésta es revisada respecto de esas cuestiones, excepto que derive de un cambio en la legislación; b) en el caso previsto en el artículo 1775 inciso c) si quien fue juzgado responsable en la acción civil es absuelto en el juicio criminal por inexistencia del hecho que funda la condena civil, o por no ser su autor; c) otros casos previstos por la ley. CAPITULO 2 Gestión de negocios", plainLanguageExplanation: "Establece el régimen de sentencia penal posterior. La sentencia penal posterior a la sentencia civil no produce ningún efecto sobre ella, excepto en el caso de revisión.", practicalEffects: ['En la práctica, este artículo rige sentencia penal posterior. La sentencia penal posterior a la sentencia civil no produce ningún efecto sobre ella, excepto en el caso de revisión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sentencia', 'penal', 'posterior', 'articulo 1780'], segments: [], amendments: [] },
  { id: 'ccyc-art-1781', lawId: 'codigo-civil-comercial', number: '1781', order: 1781, title: "Definición", text: "Definición. Hay gestión de negocios cuando una persona asume oficiosamente la gestión de un negocio ajeno por un motivo razonable, sin intención de hacer una liberalidad y sin estar autorizada ni obligada, convencional o legalmente.", plainLanguageExplanation: "Establece el régimen de definición. Hay gestión de negocios cuando una persona asume oficiosamente la gestión de un negocio ajeno por un motivo razonable, sin intención de hacer una liberalidad y sin estar autorizada ni obligada, convencional o legalmente.", practicalEffects: ['En la práctica, este artículo rige definición. Hay gestión de negocios cuando una persona asume oficiosamente la gestión de un negocio ajeno por un motivo razonable, sin intención de hacer una libe'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['definicinarticulo 1781'], segments: [], amendments: [] },
  { id: 'ccyc-art-1782', lawId: 'codigo-civil-comercial', number: '1782', order: 1782, title: "Obligaciones del gestor", text: "Obligaciones del gestor. El gestor está obligado a: a) avisar sin demora al dueño del negocio que asumió la gestión, y aguardar su respuesta, siempre que esperarla no resulte perjudicial; b) actuar conforme a la conveniencia y a la intención, real o presunta, del dueño del negocio; c) continuar la gestión hasta que el dueño del negocio tenga posibilidad de asumirla por sí mismo o, en su caso, hasta concluirla; d) proporcionar al dueño del negocio información adecuada respecto de la gestión; e) una vez concluida la gestión, rendir cuentas al dueño del negocio.", plainLanguageExplanation: "Establece el régimen de obligaciones del gestor. El gestor está obligado a: a) avisar sin demora al dueño del negocio que asumió la gestión, y aguardar su respuesta, siempre que esperarla no resulte perjudicial; b) actuar conforme a la conveniencia y a la intención, real o presunta, del dueño del negocio; c) continuar la gestió", practicalEffects: ['En la práctica, este artículo rige obligaciones del gestor. El gestor está obligado a: a) avisar sin demora al dueño del negocio que asumió la gestión, y aguardar su respuesta, siempre que esperarla no resulte'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'gestor', 'articulo 1782'], segments: [], amendments: [] },
  { id: 'ccyc-art-1783', lawId: 'codigo-civil-comercial', number: '1783', order: 1783, title: "Conclusión de la gestión", text: "Conclusión de la gestión. La gestión concluye: a) cuando el dueño le prohíbe al gestor continuar actuando. El gestor, sin embargo, puede continuarla, bajo su responsabilidad, en la medida en que lo haga por un interés propio; b) cuando el negocio concluye.", plainLanguageExplanation: "Establece el régimen de conclusión de la gestión. La gestión concluye: a) cuando el dueño le prohíbe al gestor continuar actuando.", practicalEffects: ['En la práctica, este artículo rige conclusión de la gestión. La gestión concluye: a) cuando el dueño le prohíbe al gestor continuar actuando.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusin', 'gestin', 'articulo 1783'], segments: [], amendments: [] },
  { id: 'ccyc-art-1784', lawId: 'codigo-civil-comercial', number: '1784', order: 1784, title: "Obligación frente a terceros", text: "Obligación frente a terceros. El gestor queda personalmente obligado frente a terceros. Sólo se libera si el dueño del negocio ratifica su gestión, o asume sus obligaciones; y siempre que ello no afecte a terceros de buena fe.", plainLanguageExplanation: "Establece el régimen de obligación frente a terceros. El gestor queda personalmente obligado frente a terceros.", practicalEffects: ['En la práctica, este artículo rige obligación frente a terceros. El gestor queda personalmente obligado frente a terceros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'frente', 'terceros', 'articulo 1784'], segments: [], amendments: [] },
  { id: 'ccyc-art-1785', lawId: 'codigo-civil-comercial', number: '1785', order: 1785, title: "Gestión conducida útilmente", text: "Gestión conducida útilmente. Si la gestión es conducida útilmente, el dueño del negocio está obligado frente al gestor, aunque la ventaja que debía resultar no se haya producido, o haya cesado: a) a reembolsarle el valor de los gastos necesarios y útiles, con los intereses legales desde el día en que fueron hechos; b) a liberarlo de las obligaciones personales que haya contraído a causa de la gestión; c) a repararle los daños que, por causas ajenas a su responsabilidad, haya sufrido en el ejercicio de la gestión; d) a remunerarlo, si la gestión corresponde al ejercicio de su actividad profesional, o si es equitativo en las circunstancias del caso.", plainLanguageExplanation: "Establece el régimen de gestión conducida útilmente. Si la gestión es conducida útilmente, el dueño del negocio está obligado frente al gestor, aunque la ventaja que debía resultar no se haya producido, o haya cesado: a) a reembolsarle el valor de los gastos necesarios y útiles, con los intereses legales desde el día en que fueron", practicalEffects: ['En la práctica, este artículo rige gestión conducida útilmente. Si la gestión es conducida útilmente, el dueño del negocio está obligado frente al gestor, aunque la ventaja que debía resultar no se haya producido,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gestin', 'conducida', 'tilmente', 'articulo 1785'], segments: [], amendments: [] },
  { id: 'ccyc-art-1786', lawId: 'codigo-civil-comercial', number: '1786', order: 1786, title: "Responsabilidad del gestor por culpa", text: "Responsabilidad del gestor por culpa. El gestor es responsable ante el dueño del negocio por el daño que le haya causado por su culpa. Su diligencia se aprecia con referencia concreta a su actuación en los asuntos propios; son pautas a considerar, entre otras, si se trata de una gestión urgente, si procura librar al dueño del negocio de un perjuicio, y si actúa por motivos de amistad o de afección.", plainLanguageExplanation: "Establece el régimen de responsabilidad del gestor por culpa. El gestor es responsable ante el dueño del negocio por el daño que le haya causado por su culpa.", practicalEffects: ['En la práctica, este artículo rige responsabilidad del gestor por culpa. El gestor es responsable ante el dueño del negocio por el daño que le haya causado por su culpa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'gestor', 'culpa', 'articulo 1786'], segments: [], amendments: [] },
  { id: 'ccyc-art-1787', lawId: 'codigo-civil-comercial', number: '1787', order: 1787, title: "Responsabilidad del gestor por caso fortuito", text: "Responsabilidad del gestor por caso fortuito. El gestor es responsable ante el dueño del negocio, aun por el daño que resulte de caso fortuito, excepto en cuanto la gestión le haya sido útil a aquél: a) si actúa contra su voluntad expresa; b) si emprende actividades arriesgadas, ajenas a las habituales del dueño del negocio; c) si pospone el interés del dueño del negocio frente al suyo; d) si no tiene las aptitudes necesarias para el negocio, o su intervención impide la de otra persona más idónea.", plainLanguageExplanation: "Establece el régimen de responsabilidad del gestor por caso fortuito. El gestor es responsable ante el dueño del negocio, aun por el daño que resulte de caso fortuito, excepto en cuanto la gestión le haya sido útil a aquél: a) si actúa contra su voluntad expresa; b) si emprende actividades arriesgadas, ajenas a las habituales del dueño del negocio;", practicalEffects: ['En la práctica, este artículo rige responsabilidad del gestor por caso fortuito. El gestor es responsable ante el dueño del negocio, aun por el daño que resulte de caso fortuito, excepto en cuanto la gestión le haya sido útil a aqu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'gestor', 'caso', 'fortuito', 'articulo 1787'], segments: [], amendments: [] },
  { id: 'ccyc-art-1788', lawId: 'codigo-civil-comercial', number: '1788', order: 1788, title: "Responsabilidad solidaria", text: "Responsabilidad solidaria. Son solidariamente responsables: a) los gestores que asumen conjuntamente el negocio ajeno; b) los varios dueños del negocio, frente al gestor.", plainLanguageExplanation: "Establece el régimen de responsabilidad solidaria. Son solidariamente responsables: a) los gestores que asumen conjuntamente el negocio ajeno; b) los varios dueños del negocio, frente al gestor.", practicalEffects: ['En la práctica, este artículo rige responsabilidad solidaria. Son solidariamente responsables: a) los gestores que asumen conjuntamente el negocio ajeno; b) los varios dueños del negocio, frente al gestor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'solidaria', 'articulo 1788'], segments: [], amendments: [] },
  { id: 'ccyc-art-1789', lawId: 'codigo-civil-comercial', number: '1789', order: 1789, title: "Ratificación", text: "Ratificación. El dueño del negocio queda obligado frente a los terceros por los actos cumplidos en su nombre, si ratifica la gestión, si asume las obligaciones del gestor o si la gestión es útilmente conducida.", plainLanguageExplanation: "Establece el régimen de ratificación. El dueño del negocio queda obligado frente a los terceros por los actos cumplidos en su nombre, si ratifica la gestión, si asume las obligaciones del gestor o si la gestión es útilmente conducida.", practicalEffects: ['En la práctica, este artículo rige ratificación. El dueño del negocio queda obligado frente a los terceros por los actos cumplidos en su nombre, si ratifica la gestión, si asume las obligaciones del'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ratificacinarticulo 1789'], segments: [], amendments: [] },
  { id: 'ccyc-art-1790', lawId: 'codigo-civil-comercial', number: '1790', order: 1790, title: "Aplicación de normas del mandato", text: "Aplicación de normas del mandato. Las normas del mandato se aplican supletoriamente a la gestión de negocios. Si el dueño del negocio ratifica la gestión, aunque el gestor crea hacer un negocio propio, se producen los efectos del mandato, entre partes y respecto de terceros, desde el día en que aquélla comenzó. CAPITULO 3 Empleo útil", plainLanguageExplanation: "Establece el régimen de aplicación de normas del mandato. Las normas del mandato se aplican supletoriamente a la gestión de negocios.", practicalEffects: ['En la práctica, este artículo rige aplicación de normas del mandato. Las normas del mandato se aplican supletoriamente a la gestión de negocios.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacin', 'normas', 'mandato', 'articulo 1790'], segments: [], amendments: [] },
  { id: 'ccyc-art-1791', lawId: 'codigo-civil-comercial', number: '1791', order: 1791, title: "Caracterización", text: "Caracterización. Quien, sin ser gestor de negocios ni mandatario, realiza un gasto, en interés total o parcialmente ajeno, tiene derecho a que le sea reembolsado su valor, en cuanto haya resultado de utilidad, aunque después ésta llegue a cesar. El reembolso incluye los intereses, desde la fecha en que el gasto se efectúa.", plainLanguageExplanation: "Establece el régimen de caracterización. Quien, sin ser gestor de negocios ni mandatario, realiza un gasto, en interés total o parcialmente ajeno, tiene derecho a que le sea reembolsado su valor, en cuanto haya resultado de utilidad, aunque después ésta llegue a cesar.", practicalEffects: ['En la práctica, este artículo rige caracterización. Quien, sin ser gestor de negocios ni mandatario, realiza un gasto, en interés total o parcialmente ajeno, tiene derecho a que le sea reembolsado su va'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caracterizacinarticulo 1791'], segments: [], amendments: [] },
  { id: 'ccyc-art-1792', lawId: 'codigo-civil-comercial', number: '1792', order: 1792, title: "Gastos funerarios", text: "Gastos funerarios. Están comprendidos en el artículo 1791 los gastos funerarios que tienen relación razonable con las circunstancias de la persona y los usos del lugar.", plainLanguageExplanation: "Establece el régimen de gastos funerarios. Están comprendidos en el artículo 1791 los gastos funerarios que tienen relación razonable con las circunstancias de la persona y los usos del lugar.", practicalEffects: ['En la práctica, este artículo rige gastos funerarios. Están comprendidos en el artículo 1791 los gastos funerarios que tienen relación razonable con las circunstancias de la persona y los usos del lugar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gastos', 'funerarios', 'articulo 1792'], segments: [], amendments: [] },
  { id: 'ccyc-art-1793', lawId: 'codigo-civil-comercial', number: '1793', order: 1793, title: "Obligados al reembolso", text: "Obligados al reembolso. El acreedor tiene derecho a demandar el reembolso: a) a quien recibe la utilidad; b) a los herederos del difunto, en el caso de gastos funerarios; c) al tercero adquirente a título gratuito del bien que recibe la utilidad, pero sólo hasta el valor de ella al tiempo de la adquisición. CAPITULO 4 Enriquecimiento sin causa SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de obligados al reembolso. El acreedor tiene derecho a demandar el reembolso: a) a quien recibe la utilidad; b) a los herederos del difunto, en el caso de gastos funerarios; c) al tercero adquirente a título gratuito del bien que recibe la utilidad, pero sólo hasta el valor de ella al tiempo de la adquisición.", practicalEffects: ['En la práctica, este artículo rige obligados al reembolso. El acreedor tiene derecho a demandar el reembolso: a) a quien recibe la utilidad; b) a los herederos del difunto, en el caso de gastos funerarios; c)'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligados', 'reembolso', 'articulo 1793'], segments: [], amendments: [] },
  { id: 'ccyc-art-1794', lawId: 'codigo-civil-comercial', number: '1794', order: 1794, title: "Caracterización", text: "Caracterización. Toda persona que sin una causa lícita se enriquezca a expensas de otro, está obligada, en la medida de su beneficio, a resarcir el detrimento patrimonial del empobrecido. Si el enriquecimiento consiste en la incorporación a su patrimonio de un bien determinado, debe restituirlo si subsiste en su poder al tiempo de la demanda.", plainLanguageExplanation: "Establece el régimen de caracterización. Toda persona que sin una causa lícita se enriquezca a expensas de otro, está obligada, en la medida de su beneficio, a resarcir el detrimento patrimonial del empobrecido.", practicalEffects: ['En la práctica, este artículo rige caracterización. Toda persona que sin una causa lícita se enriquezca a expensas de otro, está obligada, en la medida de su beneficio, a resarcir el detrimento patrimonial del empobrecido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caracterizacinarticulo 1794'], segments: [], amendments: [] },
  { id: 'ccyc-art-1795', lawId: 'codigo-civil-comercial', number: '1795', order: 1795, title: "Improcedencia de la acción", text: "Improcedencia de la acción. La acción no es procedente si el ordenamiento jurídico concede al damnificado otra acción para obtener la reparación del empobrecimiento sufrido. SECCION 2ª Pago indebido", plainLanguageExplanation: "Establece el régimen de improcedencia de la acción. La acción no es procedente si el ordenamiento jurídico concede al damnificado otra acción para obtener la reparación del empobrecimiento sufrido.", practicalEffects: ['En la práctica, este artículo rige improcedencia de la acción. La acción no es procedente si el ordenamiento jurídico concede al damnificado otra acción para obtener la reparación del empobrecimiento sufrido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['improcedencia', 'accin', 'articulo 1795'], segments: [], amendments: [] },
  { id: 'ccyc-art-1796', lawId: 'codigo-civil-comercial', number: '1796', order: 1796, title: "Casos", text: "Casos. El pago es repetible, si: a) la causa de deber no existe, o no subsiste, porque no hay obligación válida; esa causa deja de existir; o es realizado en consideración a una causa futura, que no se va a producir; b) paga quien no está obligado, o no lo está en los alcances en que paga, a menos que lo haga como tercero; c) recibe el pago quien no es acreedor, a menos que se entregue como liberalidad; d) la causa del pago es ilícita o inmoral; e) el pago es obtenido por medios ilícitos.", plainLanguageExplanation: "Establece el régimen de casos. El pago es repetible, si: a) la causa de deber no existe, o no subsiste, porque no hay obligación válida; esa causa deja de existir; o es realizado en consideración a una causa futura, que no se va a producir; b) paga quien no está obligado, o no lo está en los alcances en que pa", practicalEffects: ['En la práctica, este artículo rige casos. El pago es repetible, si: a) la causa de deber no existe, o no subsiste, porque no hay obligación válida; esa causa deja de existir; o es realizado en'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casosarticulo 1796'], segments: [], amendments: [] },
  { id: 'ccyc-art-1797', lawId: 'codigo-civil-comercial', number: '1797', order: 1797, title: "Irrelevancia del error", text: "Irrelevancia del error. La repetición del pago no está sujeta a que haya sido hecho con error.", plainLanguageExplanation: "Establece el régimen de irrelevancia del error. La repetición del pago no está sujeta a que haya sido hecho con error.", practicalEffects: ['En la práctica, este artículo rige irrelevancia del error. La repetición del pago no está sujeta a que haya sido hecho con error.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['irrelevancia', 'error', 'articulo 1797'], segments: [], amendments: [] },
  { id: 'ccyc-art-1798', lawId: 'codigo-civil-comercial', number: '1798', order: 1798, title: "Alcances de la repetición", text: "Alcances de la repetición. La repetición obliga a restituir lo recibido, conforme a las reglas de las obligaciones de dar para restituir.", plainLanguageExplanation: "Establece el régimen de alcances de la repetición. La repetición obliga a restituir lo recibido, conforme a las reglas de las obligaciones de dar para restituir.", practicalEffects: ['En la práctica, este artículo rige alcances de la repetición. La repetición obliga a restituir lo recibido, conforme a las reglas de las obligaciones de dar para restituir.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alcances', 'repeticin', 'articulo 1798'], segments: [], amendments: [] },
  { id: 'ccyc-art-1799', lawId: 'codigo-civil-comercial', number: '1799', order: 1799, title: "Situaciones especiales", text: "Situaciones especiales. En particular: a) la restitución a cargo de una persona incapaz o con capacidad restringida no puede exceder el provecho que haya obtenido; b) en el caso del inciso b) del artículo 1796, la restitución no procede si el acreedor, de buena fe, se priva de su título, o renuncia a las garantías; quien realiza el pago tiene subrogación legal en los derechos de aquél; c) en el caso del inciso d) del artículo 1796, la parte que no actúa con torpeza tiene derecho a la restitución; si ambas partes actúan torpemente, el crédito tiene el mismo destino que las herencias vacantes. CAPITULO 5 Declaración unilateral de voluntad SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de situaciones especiales. En particular: a) la restitución a cargo de una persona incapaz o con capacidad restringida no puede exceder el provecho que haya obtenido; b) en el caso del inciso b) del artículo 1796, la restitución no procede si el acreedor, de buena fe, se priva de su título, o renuncia a la", practicalEffects: ['En la práctica, este artículo rige situaciones especiales. En particular: a) la restitución a cargo de una persona incapaz o con capacidad restringida no puede exceder el provecho que haya obtenido; b) en el c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['situaciones', 'especiales', 'articulo 1799'], segments: [], amendments: [] },
  { id: 'ccyc-art-1800', lawId: 'codigo-civil-comercial', number: '1800', order: 1800, title: "Regla general", text: "Regla general. La declaración unilateral de voluntad causa una obligación jurídicamente exigible en los casos previstos por la ley o por los usos y costumbres. Se le aplican subsidiariamente las normas relativas a los contratos.", plainLanguageExplanation: "Establece el régimen de regla general. La declaración unilateral de voluntad causa una obligación jurídicamente exigible en los casos previstos por la ley o por los usos y costumbres.", practicalEffects: ['En la práctica, este artículo rige regla general. La declaración unilateral de voluntad causa una obligación jurídicamente exigible en los casos previstos por la ley o por los usos y costumbres.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['regla', 'general', 'articulo 1800'], segments: [], amendments: [] },
  { id: 'ccyc-art-1801', lawId: 'codigo-civil-comercial', number: '1801', order: 1801, title: "Reconocimiento y promesa de pago", text: "Reconocimiento y promesa de pago. La promesa de pago de una obligación realizada unilateralmente hace presumir la existencia de una fuente válida, excepto prueba en contrario. Para el reconocimiento se aplica el artículo 733.", plainLanguageExplanation: "Establece el régimen de reconocimiento y promesa de pago. La promesa de pago de una obligación realizada unilateralmente hace presumir la existencia de una fuente válida, excepto prueba en contrario.", practicalEffects: ['En la práctica, este artículo rige reconocimiento y promesa de pago. La promesa de pago de una obligación realizada unilateralmente hace presumir la existencia de una fuente válida, excepto prueba en contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reconocimiento', 'promesa', 'pago', 'articulo 1801'], segments: [], amendments: [] },
  { id: 'ccyc-art-1802', lawId: 'codigo-civil-comercial', number: '1802', order: 1802, title: "Cartas de crédito", text: "Cartas de crédito. Las obligaciones que resultan para el emisor o confirmante de las cartas de crédito emitidas por bancos u otras entidades autorizadas son declaraciones unilaterales de voluntad. En estos casos puede utilizarse cualquier clase de instrumento particular. SECCION 2ª Promesa pública de recompensa", plainLanguageExplanation: "Establece el régimen de cartas de crédito. Las obligaciones que resultan para el emisor o confirmante de las cartas de crédito emitidas por bancos u otras entidades autorizadas son declaraciones unilaterales de voluntad.", practicalEffects: ['En la práctica, este artículo rige cartas de crédito. Las obligaciones que resultan para el emisor o confirmante de las cartas de crédito emitidas por bancos u otras entidades autorizadas son declaraciones unilaterales de voluntad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cartas', 'crdito', 'articulo 1802'], segments: [], amendments: [] },
  { id: 'ccyc-art-1803', lawId: 'codigo-civil-comercial', number: '1803', order: 1803, title: "Obligatoriedad", text: "Obligatoriedad. El que mediante anuncios públicos promete recompensar, con una prestación pecuniaria o una distinción, a quien ejecute determinado acto, cumpla determinados requisitos o se encuentre en cierta situación, queda obligado por esa promesa desde el momento en que llega a conocimiento del público.", plainLanguageExplanation: "Establece el régimen de obligatoriedad. El que mediante anuncios públicos promete recompensar, con una prestación pecuniaria o una distinción, a quien ejecute determinado acto, cumpla determinados requisitos o se encuentre en cierta situación, queda obligado por esa promesa desde el momento en que llega a conocimiento", practicalEffects: ['En la práctica, este artículo rige obligatoriedad. El que mediante anuncios públicos promete recompensar, con una prestación pecuniaria o una distinción, a quien ejecute determinado acto, cumpla determ'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligatoriedadarticulo 1803'], segments: [], amendments: [] },
  { id: 'ccyc-art-1804', lawId: 'codigo-civil-comercial', number: '1804', order: 1804, title: "Plazo expreso o tácito", text: "Plazo expreso o tácito. La promesa formulada sin plazo, expreso ni tácito, caduca dentro del plazo de seis meses del último acto de publicidad, si nadie comunica al promitente el acaecimiento del hecho o de la situación prevista.", plainLanguageExplanation: "Establece el régimen de plazo expreso o tácito. La promesa formulada sin plazo, expreso ni tácito, caduca dentro del plazo de seis meses del último acto de publicidad, si nadie comunica al promitente el acaecimiento del hecho o de la situación prevista.", practicalEffects: ['En la práctica, este artículo rige plazo expreso o tácito. La promesa formulada sin plazo, expreso ni tácito, caduca dentro del plazo de seis meses del último acto de publicidad, si nadie comunica al promitent'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plazo', 'expreso', 'tcito', 'articulo 1804'], segments: [], amendments: [] },
  { id: 'ccyc-art-1805', lawId: 'codigo-civil-comercial', number: '1805', order: 1805, title: "Revocación", text: "Revocación. La promesa sin plazo puede ser retractada en todo tiempo por el promitente. Si tiene plazo, sólo puede revocarse antes del vencimiento, con justa causa. En ambos casos, la revocación surte efecto desde que es hecha pública por un medio de publicidad idéntico o equivalente al utilizado para la promesa. Es inoponible a quien ha efectuado el hecho o verificado la situación prevista antes del primer acto de publicidad de la revocación.", plainLanguageExplanation: "Establece el régimen de revocación. La promesa sin plazo puede ser retractada en todo tiempo por el promitente.", practicalEffects: ['En la práctica, este artículo rige revocación. La promesa sin plazo puede ser retractada en todo tiempo por el promitente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacinarticulo 1805'], segments: [], amendments: [] },
  { id: 'ccyc-art-1806', lawId: 'codigo-civil-comercial', number: '1806', order: 1806, title: "Atribución de la recompensa", text: "Atribución de la recompensa. Cooperación de varias personas. Si varias personas acreditan por separado el cumplimiento del hecho, los requisitos o la situación previstos en la promesa, la recompensa corresponde a quien primero lo ha comunicado al promitente en forma fehaciente. Si la notificación es simultánea, el promitente debe distribuir la recompensa en partes iguales; si la prestación es indivisible, la debe atribuir por sorteo. Si varias personas contribuyen a un mismo resultado, se aplica lo que los contribuyentes han convenido y puesto en conocimiento del promitente por medio fehaciente. A falta de notificación de convenio unánime, el promitente entrega lo prometido por partes iguales a todos y, si es indivisible, lo atribuye por sorteo; sin perjuicio de las acciones entre los contribuyentes, las que en todos los casos se dirimen por amigables componedores. SECCION 3ª Concurso público", plainLanguageExplanation: "Establece el régimen de atribución de la recompensa. Cooperación de varias personas.", practicalEffects: ['En la práctica, este artículo rige atribución de la recompensa. Cooperación de varias personas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribucin', 'recompensa', 'articulo 1806'], segments: [], amendments: [] },
  { id: 'ccyc-art-1807', lawId: 'codigo-civil-comercial', number: '1807', order: 1807, title: "Concurso público", text: "Concurso público. La promesa de recompensa al vencedor de un concurso, requiere para su validez que el anuncio respectivo contenga el plazo de presentación de los interesados y de realización de los trabajos previstos. El dictamen del jurado designado en los anuncios obliga a los interesados. A falta de designación, se entiende que la adjudicación queda reservada al promitente. El promitente no puede exigir la cesión de los derechos pecuniarios sobre la obra premiada si esa transmisión no fue prevista en las bases del concurso.", plainLanguageExplanation: "Establece el régimen de concurso público. La promesa de recompensa al vencedor de un concurso, requiere para su validez que el anuncio respectivo contenga el plazo de presentación de los interesados y de realización de los trabajos previstos.", practicalEffects: ['En la práctica, este artículo rige concurso público. La promesa de recompensa al vencedor de un concurso, requiere para su validez que el anuncio respectivo contenga el plazo de presentación de los interesados y de realización de los trabajos previstos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concurso', 'pblico', 'articulo 1807'], segments: [], amendments: [] },
  { id: 'ccyc-art-1808', lawId: 'codigo-civil-comercial', number: '1808', order: 1808, title: "Destinatarios", text: "Destinatarios. La promesa referida en el artículo 1807 puede ser efectuada respecto de cualquier persona o personas determinadas por ciertas calidades que deben ser claramente anunciadas. No pueden efectuarse llamados que realicen diferencias arbitrarias por raza, sexo, religión, ideología, nacionalidad, opinión política o gremial, posición económica o social, o basadas en otra discriminación ilegal.", plainLanguageExplanation: "Establece el régimen de destinatarios. La promesa referida en el artículo 1807 puede ser efectuada respecto de cualquier persona o personas determinadas por ciertas calidades que deben ser claramente anunciadas.", practicalEffects: ['En la práctica, este artículo rige destinatarios. La promesa referida en el artículo 1807 puede ser efectuada respecto de cualquier persona o personas determinadas por ciertas calidades que deben ser claramente anunciadas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['destinatariosarticulo 1808'], segments: [], amendments: [] },
  { id: 'ccyc-art-1809', lawId: 'codigo-civil-comercial', number: '1809', order: 1809, title: "Decisión del jurado", text: "Decisión del jurado. El dictamen del jurado obliga a los interesados. Si el jurado decide que todos o varios de los concursantes tienen el mismo mérito, el premio es distribuido en partes iguales entre los designados. Si el premio es indivisible, se adjudica por sorteo. El jurado puede declarar desierto cualquiera de los premios llamados a concurso. SECCION 4ª Garantías unilaterales", plainLanguageExplanation: "Establece el régimen de decisión del jurado. El dictamen del jurado obliga a los interesados.", practicalEffects: ['En la práctica, este artículo rige decisión del jurado. El dictamen del jurado obliga a los interesados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['decisin', 'jurado', 'articulo 1809'], segments: [], amendments: [] },
  { id: 'ccyc-art-1810', lawId: 'codigo-civil-comercial', number: '1810', order: 1810, title: "Garantías unilaterales", text: "Garantías unilaterales. Constituyen una declaración unilateral de voluntad y están regidas por las disposiciones de este Capítulo las llamadas 'garantías de cumplimiento a primera demanda', 'a primer requerimiento' y aquellas en que de cualquier otra manera se establece que el emisor garantiza el cumplimiento de las obligaciones de otro y se obliga a pagarlas, o a pagar una suma de dinero u otra prestación determinada, independientemente de las excepciones o defensas que el ordenante pueda tener, aunque mantenga el derecho de repetición contra el beneficiario, el ordenante o ambos. El pago faculta a la promoción de las acciones recursorias correspondientes. En caso de fraude o abuso manifiestos del beneficiario que surjan de prueba instrumental u otra de fácil y rápido examen, el garante o el ordenante puede requerir que el juez fije una caución adecuada que el beneficiario debe satisfacer antes del cobro.", plainLanguageExplanation: "Establece el régimen de garantías unilaterales. Constituyen una declaración unilateral de voluntad y están regidas por las disposiciones de este Capítulo las llamadas 'garantías de cumplimiento a primera demanda', 'a primer requerimiento' y aquellas en que de cualquier otra manera se establece que el emisor garantiza el cumpli", practicalEffects: ['En la práctica, este artículo rige garantías unilaterales. Constituyen una declaración unilateral de voluntad y están regidas por las disposiciones de este Capítulo las llamadas \'garantías de cumplimiento a pr'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garantas', 'unilaterales', 'articulo 1810'], segments: [], amendments: [] },
  { id: 'ccyc-art-1811', lawId: 'codigo-civil-comercial', number: '1811', order: 1811, title: "Sujetos", text: "Sujetos. Pueden emitir esta clase de garantías: a) las personas públicas; b) las personas jurídicas privadas en las que sus socios, fundadores o integrantes no responden ilimitadamente; c) en cualquier caso, las entidades financieras y compañías de seguros, y los importadores y exportadores por operaciones de comercio exterior, sean o no parte directa en ellas.", plainLanguageExplanation: "Establece el régimen de sujetos. Pueden emitir esta clase de garantías: a) las personas públicas; b) las personas jurídicas privadas en las que sus socios, fundadores o integrantes no responden ilimitadamente; c) en cualquier caso, las entidades financieras y compañías de seguros, y los importadores y exportador", practicalEffects: ['En la práctica, este artículo rige sujetos. Pueden emitir esta clase de garantías: a) las personas públicas; b) las personas jurídicas privadas en las que sus socios, fundadores o integrantes no'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sujetosarticulo 1811'], segments: [], amendments: [] },
  { id: 'ccyc-art-1812', lawId: 'codigo-civil-comercial', number: '1812', order: 1812, title: "Forma", text: "Forma. Las garantías previstas en esta Sección deben constar en instrumento público o privado. Si son otorgadas por entidades financieras o compañías de seguros, pueden asumirse también en cualquier clase de instrumento particular.", plainLanguageExplanation: "Establece el régimen de forma. Las garantías previstas en esta Sección deben constar en instrumento público o privado.", practicalEffects: ['En la práctica, este artículo rige forma. Las garantías previstas en esta Sección deben constar en instrumento público o privado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formaarticulo 1812'], segments: [], amendments: [] },
  { id: 'ccyc-art-1813', lawId: 'codigo-civil-comercial', number: '1813', order: 1813, title: "Cesión de garantía", text: "Cesión de garantía. Los derechos del beneficiario emergentes de la garantía no pueden transmitirse separadamente del contrato o relación con la que la garantía está funcionalmente vinculada, antes de acaecer el incumplimiento o el plazo que habilita el reclamo contra el emisor, excepto pacto en contrario. Una vez ocurrido el hecho o vencido el plazo que habilita ese reclamo, los derechos del beneficiario pueden ser cedidos independientemente de cualquier otra relación. Sin perjuicio de ello, el cesionario queda vinculado a las eventuales acciones de repetición que puedan corresponder contra el beneficiario según la garantía.", plainLanguageExplanation: "Establece el régimen de cesión de garantía. Los derechos del beneficiario emergentes de la garantía no pueden transmitirse separadamente del contrato o relación con la que la garantía está funcionalmente vinculada, antes de acaecer el incumplimiento o el plazo que habilita el reclamo contra el emisor, excepto pacto en contrario.", practicalEffects: ['En la práctica, este artículo rige cesión de garantía. Los derechos del beneficiario emergentes de la garantía no pueden transmitirse separadamente del contrato o relación con la que la garantía está funci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cesin', 'garanta', 'articulo 1813'], segments: [], amendments: [] },
  { id: 'ccyc-art-1814', lawId: 'codigo-civil-comercial', number: '1814', order: 1814, title: "Irrevocabilidad", text: "Irrevocabilidad. La garantía unilateral es irrevocable a menos que se disponga en el acto de su creación que es revocable. CAPITULO 6 Títulos valores SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de irrevocabilidad. La garantía unilateral es irrevocable a menos que se disponga en el acto de su creación que es revocable.", practicalEffects: ['En la práctica, este artículo rige irrevocabilidad. La garantía unilateral es irrevocable a menos que se disponga en el acto de su creación que es revocable.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['irrevocabilidadarticulo 1814'], segments: [], amendments: [] },
  { id: 'ccyc-art-1815', lawId: 'codigo-civil-comercial', number: '1815', order: 1815, title: "Concepto", text: "Concepto. Los títulos valores incorporan una obligación incondicional e irrevocable de una prestación y otorgan a cada titular un derecho autónomo, sujeto a lo previsto en el artículo 1816. Cuando en este Código se hace mención a bienes o cosas muebles registrables, no se comprenden los títulos valores.", plainLanguageExplanation: "Establece el régimen de concepto. Los títulos valores incorporan una obligación incondicional e irrevocable de una prestación y otorgan a cada titular un derecho autónomo, sujeto a lo previsto en el artículo 1816.", practicalEffects: ['En la práctica, este artículo rige concepto. Los títulos valores incorporan una obligación incondicional e irrevocable de una prestación y otorgan a cada titular un derecho autónomo, sujeto a lo previsto en el artículo 1816.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1815'], segments: [], amendments: [] },
  { id: 'ccyc-art-1816', lawId: 'codigo-civil-comercial', number: '1816', order: 1816, title: "Autonomía", text: "Autonomía. El portador de buena fe de un título valor que lo adquiere conforme con su ley de circulación, tiene un derecho autónomo, y le son inoponibles las defensas personales que pueden existir contra anteriores portadores. A los efectos de este artículo, el portador es de mala fe si al adquirir el título procede a sabiendas en perjuicio del deudor demandado.", plainLanguageExplanation: "Establece el régimen de autonomía. El portador de buena fe de un título valor que lo adquiere conforme con su ley de circulación, tiene un derecho autónomo, y le son inoponibles las defensas personales que pueden existir contra anteriores portadores.", practicalEffects: ['En la práctica, este artículo rige autonomía. El portador de buena fe de un título valor que lo adquiere conforme con su ley de circulación, tiene un derecho autónomo, y le son inoponibles las def'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['autonomaarticulo 1816'], segments: [], amendments: [] },
  { id: 'ccyc-art-1817', lawId: 'codigo-civil-comercial', number: '1817', order: 1817, title: "Pago liberatorio", text: "Pago liberatorio. El deudor que paga al portador del título valor conforme con su ley de circulación queda liberado, excepto que al momento del pago, disponga de pruebas que de-muestren la mala fe del que lo requiere. Sin embargo, si el deudor no recibe el título valor, se aplica lo dispuesto por el artículo 1819.", plainLanguageExplanation: "Establece el régimen de pago liberatorio. El deudor que paga al portador del título valor conforme con su ley de circulación queda liberado, excepto que al momento del pago, disponga de pruebas que de-muestren la mala fe del que lo requiere.", practicalEffects: ['En la práctica, este artículo rige pago liberatorio. El deudor que paga al portador del título valor conforme con su ley de circulación queda liberado, excepto que al momento del pago, disponga de pruebas que de-muestren la mala fe del que lo requiere.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pago', 'liberatorio', 'articulo 1817'], segments: [], amendments: [] },
  { id: 'ccyc-art-1818', lawId: 'codigo-civil-comercial', number: '1818', order: 1818, title: "Accesorios", text: "Accesorios. La transferencia de un título valor comprende los accesorios que son inherentes a la prestación en él incorporada.", plainLanguageExplanation: "Establece el régimen de accesorios. La transferencia de un título valor comprende los accesorios que son inherentes a la prestación en él incorporada.", practicalEffects: ['En la práctica, este artículo rige accesorios. La transferencia de un título valor comprende los accesorios que son inherentes a la prestación en él incorporada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accesoriosarticulo 1818'], segments: [], amendments: [] },
  { id: 'ccyc-art-1819', lawId: 'codigo-civil-comercial', number: '1819', order: 1819, title: "Titularidad", text: "Titularidad. Quien adquiere un título valor a título oneroso, sin culpa grave y conforme con su ley de circulación, no está obligado a desprenderse del título valor y, en su caso, no está sujeto a reivindicación ni a la repetición de lo cobrado.", plainLanguageExplanation: "Establece el régimen de titularidad. Quien adquiere un título valor a título oneroso, sin culpa grave y conforme con su ley de circulación, no está obligado a desprenderse del título valor y, en su caso, no está sujeto a reivindicación ni a la repetición de lo cobrado.", practicalEffects: ['En la práctica, este artículo rige titularidad. Quien adquiere un título valor a título oneroso, sin culpa grave y conforme con su ley de circulación, no está obligado a desprenderse del título valo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['titularidadarticulo 1819'], segments: [], amendments: [] },
  { id: 'ccyc-art-1820', lawId: 'codigo-civil-comercial', number: '1820', order: 1820, title: "Libertad de creación", text: "Libertad de creación. Cualquier persona puede crear y emitir títulos valores en los tipos y condiciones que elija. Se comprende en esta facultad la denominación del tipo o clase de título, su forma de circulación con arreglo a las leyes generales, sus garantías, rescates, plazos, su calidad de convertible o no en otra clase de título, derechos de los terceros titulares y demás regulaciones que hacen a la configuración de los derechos de las partes interesadas, que deben expresarse con claridad y no prestarse a confusión con el tipo, denominación y condiciones de los títulos valores especialmente previstos en la legislación vigente. Sólo pueden emitirse títulos valores abstractos no regulados por la ley cuando se destinan a ofertas públicas, con el cumplimiento de los recaudos de la legislación específica; y también cuando los emisores son entidades financieras, de seguros o fiduciarios financieros registrados ante el organismo de contralor de los mercados de valores.", plainLanguageExplanation: "Establece el régimen de libertad de creación. Cualquier persona puede crear y emitir títulos valores en los tipos y condiciones que elija.", practicalEffects: ['En la práctica, este artículo rige libertad de creación. Cualquier persona puede crear y emitir títulos valores en los tipos y condiciones que elija.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'creacin', 'articulo 1820'], segments: [], amendments: [] },
  { id: 'ccyc-art-1821', lawId: 'codigo-civil-comercial', number: '1821', order: 1821, title: "Defensas oponibles", text: "Defensas oponibles. El deudor sólo puede oponer al portador del título valor las siguientes defensas: a) las personales que tiene respecto de él, excepto el caso de transmisiones en procuración, o fiduciarias con análoga finalidad; b) las que derivan del tenor literal del título o, en su caso, del tenor del documento inscripto de conformidad con el artículo 1850; c) las que se fundan en la falsedad de su firma o en un defecto de capacidad o de representación al momento en que se constituye su obligación, excepto que la autovía de la firma o de la declaración obligatoria sea consentida o asumida como propia o que la actuación del representante sea ratificada; d) las que se derivan de la falta de legitimación del portador; e) la de alteración del texto del título o, en su caso, del texto inscripto según el artículo 1850; f) las de prescripción o caducidad; g) las que se fundan en la cancelación del título valor o en la suspensión de su pago ordenada conforme a lo previsto en este Capítulo; h) las de carácter procesal que establecen las leyes respectivas.", plainLanguageExplanation: "Establece el régimen de defensas oponibles. El deudor sólo puede oponer al portador del título valor las siguientes defensas: a) las personales que tiene respecto de él, excepto el caso de transmisiones en procuración, o fiduciarias con análoga finalidad; b) las que derivan del tenor literal del título o, en su caso, del t", practicalEffects: ['En la práctica, este artículo rige defensas oponibles. El deudor sólo puede oponer al portador del título valor las siguientes defensas: a) las personales que tiene respecto de él, excepto el caso de trans'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['defensas', 'oponibles', 'articulo 1821'], segments: [], amendments: [] },
  { id: 'ccyc-art-1822', lawId: 'codigo-civil-comercial', number: '1822', order: 1822, title: "Medidas precautorias", text: "Medidas precautorias. Las medidas precautorias, secuestro, gravámenes y cualquier otra afectación del derecho conferido por el título valor, no tienen efecto si no se llevan a cabo: a) en los títulos valores al portador, a la orden o nominativos endosables, sobre el mismo documento; b) en los títulos nominativos no endosables, y en los no cartulares, por su inscripción en el registro respectivo; c) cuando un título valor se ha ingresado a una caja de valores o a una cámara compensadora o sistema de compensación autorizado, la medida debe notificarse a la entidad pertinente, la que la debe registrar conforme con sus reglamentos.", plainLanguageExplanation: "Establece el régimen de medidas precautorias. Las medidas precautorias, secuestro, gravámenes y cualquier otra afectación del derecho conferido por el título valor, no tienen efecto si no se llevan a cabo: a) en los títulos valores al portador, a la orden o nominativos endosables, sobre el mismo documento; b) en los títulos", practicalEffects: ['En la práctica, este artículo rige medidas precautorias. Las medidas precautorias, secuestro, gravámenes y cualquier otra afectación del derecho conferido por el título valor, no tienen efecto si no se lleva'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'precautorias', 'articulo 1822'], segments: [], amendments: [] },
  { id: 'ccyc-art-1823', lawId: 'codigo-civil-comercial', number: '1823', order: 1823, title: "Firmas falsas y otros supuestos", text: "Firmas falsas y otros supuestos. Aunque por cualquier motivo el título valor contenga firmas falsas, o de personas inexistentes o que no resulten obligadas por la firma, son válidas las obligaciones de los demás suscriptores, y se aplica lo dispuesto por el artículo 1819.", plainLanguageExplanation: "Establece el régimen de firmas falsas y otros supuestos. Aunque por cualquier motivo el título valor contenga firmas falsas, o de personas inexistentes o que no resulten obligadas por la firma, son válidas las obligaciones de los demás suscriptores, y se aplica lo dispuesto por el artículo 1819.", practicalEffects: ['En la práctica, este artículo rige firmas falsas y otros supuestos. Aunque por cualquier motivo el título valor contenga firmas falsas, o de personas inexistentes o que no resulten obligadas por la firma, son válidas l'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['firmas', 'falsas', 'otros', 'supuestos', 'articulo 1823'], segments: [], amendments: [] },
  { id: 'ccyc-art-1824', lawId: 'codigo-civil-comercial', number: '1824', order: 1824, title: "Incumplimiento del asentimiento conyugal", text: "Incumplimiento del asentimiento conyugal. El incumplimiento del requisito previsto en el artículo 470, inciso b) en los títulos nominativos no endosables o no cartulares, no es oponible a terceros portadores de buena fe. Al efecto previsto por este artículo, se considera de buena fe al adquirente de un título valor incorporado al régimen de oferta pública.", plainLanguageExplanation: "Establece el régimen de incumplimiento del asentimiento conyugal. El incumplimiento del requisito previsto en el artículo 470, inciso b) en los títulos nominativos no endosables o no cartulares, no es oponible a terceros portadores de buena fe.", practicalEffects: ['En la práctica, este artículo rige incumplimiento del asentimiento conyugal. El incumplimiento del requisito previsto en el artículo 470, inciso b) en los títulos nominativos no endosables o no cartulares, no es oponible a terceros portadores de buena fe.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incumplimiento', 'asentimiento', 'conyugal', 'articulo 1824'], segments: [], amendments: [] },
  { id: 'ccyc-art-1825', lawId: 'codigo-civil-comercial', number: '1825', order: 1825, title: "Representación inexistente o insuficiente", text: "Representación inexistente o insuficiente. Quien invoca una representación inexistente o actúa sin facultades suficientes, es personalmente responsable como si actuara en nombre propio. Igual responsabilidad tiene quien falsifica la firma incorporada a un título valor.", plainLanguageExplanation: "Establece el régimen de representación inexistente o insuficiente. Quien invoca una representación inexistente o actúa sin facultades suficientes, es personalmente responsable como si actuara en nombre propio.", practicalEffects: ['En la práctica, este artículo rige representación inexistente o insuficiente. Quien invoca una representación inexistente o actúa sin facultades suficientes, es personalmente responsable como si actuara en nombre propio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representacin', 'inexistente', 'insuficiente', 'articulo 1825'], segments: [], amendments: [] },
  { id: 'ccyc-art-1826', lawId: 'codigo-civil-comercial', number: '1826', order: 1826, title: "Responsabilidad", text: "Responsabilidad. Excepto disposición legal o cláusula expresa en el título valor o en uno de sus actos de transmisión o garantía, están solidariamente obligados al pago los creadores del título valor, pero no los demás intervinientes. Las obligaciones resultantes de un título valor pueden ser garantizadas por todas las garantías que sean compatibles. Las garantías otorgadas en el texto del documento o que surgen de la inscripción del artículo 1850, son invocables por todos los titulares y, si no hay disposición expresa en contrario, se consideran solidarias con las de los otros obligados.", plainLanguageExplanation: "Establece el régimen de responsabilidad. Excepto disposición legal o cláusula expresa en el título valor o en uno de sus actos de transmisión o garantía, están solidariamente obligados al pago los creadores del título valor, pero no los demás intervinientes.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. Excepto disposición legal o cláusula expresa en el título valor o en uno de sus actos de transmisión o garantía, están solidariamente obligados al pag'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 1826'], segments: [], amendments: [] },
  { id: 'ccyc-art-1827', lawId: 'codigo-civil-comercial', number: '1827', order: 1827, title: "Novación", text: "Novación. Excepto novación, la creación o transmisión de un título valor no perjudica las acciones derivadas del negocio causal o subyacente. El portador sólo puede ejercer la acción causal contra el deudor requerido si el título valor no está perjudicado, y ofrece su restitución si el título valor es cartular. Si el portador ha perdido las acciones emergentes del título valor y no tiene acción causal, se aplica lo dispuesto sobre enriquecimiento sin causa.", plainLanguageExplanation: "Establece el régimen de novación. Excepto novación, la creación o transmisión de un título valor no perjudica las acciones derivadas del negocio causal o subyacente.", practicalEffects: ['En la práctica, este artículo rige novación. Excepto novación, la creación o transmisión de un título valor no perjudica las acciones derivadas del negocio causal o subyacente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['novacinarticulo 1827'], segments: [], amendments: [] },
  { id: 'ccyc-art-1828', lawId: 'codigo-civil-comercial', number: '1828', order: 1828, title: "Títulos representativos de mercaderías", text: "Títulos representativos de mercaderías. Los títulos representativos de mercaderías atribuyen al portador legítimo el derecho a la entrega de la cosa, su posesión y el poder de disponerla mediante la transferencia del título.", plainLanguageExplanation: "Establece el régimen de títulos representativos de mercaderías. Los títulos representativos de mercaderías atribuyen al portador legítimo el derecho a la entrega de la cosa, su posesión y el poder de disponerla mediante la transferencia del título.", practicalEffects: ['En la práctica, este artículo rige títulos representativos de mercaderías. Los títulos representativos de mercaderías atribuyen al portador legítimo el derecho a la entrega de la cosa, su posesión y el poder de disponerla med'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ttulos', 'representativos', 'mercaderas', 'articulo 1828'], segments: [], amendments: [] },
  { id: 'ccyc-art-1829', lawId: 'codigo-civil-comercial', number: '1829', order: 1829, title: "Cuotapartes de fondos comunes de inversión", text: "Cuotapartes de fondos comunes de inversión. Son títulos valores las cuotapartes de fondos comunes de inversión. SECCION 2ª Títulos valores cartulares", plainLanguageExplanation: "Establece el régimen de cuotapartes de fondos comunes de inversión. Son títulos valores las cuotapartes de fondos comunes de inversión.", practicalEffects: ['En la práctica, este artículo rige cuotapartes de fondos comunes de inversión. Son títulos valores las cuotapartes de fondos comunes de inversión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cuotapartes', 'fondos', 'comunes', 'inversin', 'articulo 1829'], segments: [], amendments: [] },
  { id: 'ccyc-art-1830', lawId: 'codigo-civil-comercial', number: '1830', order: 1830, title: "Necesidad", text: "Necesidad. Los títulos valores cartulares son necesarios para la creación, transmisión, modificación y ejercicio del derecho incorporado.", plainLanguageExplanation: "Establece el régimen de necesidad. Los títulos valores cartulares son necesarios para la creación, transmisión, modificación y ejercicio del derecho incorporado.", practicalEffects: ['En la práctica, este artículo rige necesidad. Los títulos valores cartulares son necesarios para la creación, transmisión, modificación y ejercicio del derecho incorporado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['necesidadarticulo 1830'], segments: [], amendments: [] },
  { id: 'ccyc-art-1831', lawId: 'codigo-civil-comercial', number: '1831', order: 1831, title: "Literalidad", text: "Literalidad. El tenor literal del documento determina el alcance y las modalidades de los derechos y obligaciones consignadas en él, o en su hoja de prolongación.", plainLanguageExplanation: "Establece el régimen de literalidad. El tenor literal del documento determina el alcance y las modalidades de los derechos y obligaciones consignadas en él, o en su hoja de prolongación.", practicalEffects: ['En la práctica, este artículo rige literalidad. El tenor literal del documento determina el alcance y las modalidades de los derechos y obligaciones consignadas en él, o en su hoja de prolongación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['literalidadarticulo 1831'], segments: [], amendments: [] },
  { id: 'ccyc-art-1832', lawId: 'codigo-civil-comercial', number: '1832', order: 1832, title: "Alteraciones", text: "Alteraciones. En caso de alteración del texto de un título valor cartular, los firmantes posteriores quedan obligados en los términos del texto alterado; los firmantes anteriores están obligados en los términos del texto original. Si no resulta del título valor o no se demuestra que la firma fue puesta después de la alteración, se presume que ha sido puesta antes.", plainLanguageExplanation: "Establece el régimen de alteraciones. En caso de alteración del texto de un título valor cartular, los firmantes posteriores quedan obligados en los términos del texto alterado; los firmantes anteriores están obligados en los términos del texto original.", practicalEffects: ['En la práctica, este artículo rige alteraciones. En caso de alteración del texto de un título valor cartular, los firmantes posteriores quedan obligados en los términos del texto alterado; los firman'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alteracionesarticulo 1832'], segments: [], amendments: [] },
  { id: 'ccyc-art-1833', lawId: 'codigo-civil-comercial', number: '1833', order: 1833, title: "Requisitos", text: "Requisitos. Contenido mínimo. Cuando por ley o por disposición del creador, el título valor debe incluir un contenido particular con carácter esencial, no produce efecto cuando no contiene esas enunciaciones. El título valor en el que se omiten las referidas menciones al tiempo de su creación, puede ser completado hasta la fecha en que debe cumplirse la prestación, excepto disposición en contrario.", plainLanguageExplanation: "Establece el régimen de requisitos. Contenido mínimo.", practicalEffects: ['En la práctica, este artículo rige requisitos. Contenido mínimo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['requisitosarticulo 1833'], segments: [], amendments: [] },
  { id: 'ccyc-art-1834', lawId: 'codigo-civil-comercial', number: '1834', order: 1834, title: "Aplicación subsidiaria", text: "Aplicación subsidiaria. Las normas de esta Sección: a) se aplican en subsidio de las especiales que rigen para títulos valores determinados; b) no se aplican cuando leyes especiales así lo disponen, incluso en cuanto ellas se refieren a la obligatoriedad de alguna forma de creación o circulación de los títulos valores o de clases de ellos.", plainLanguageExplanation: "Establece el régimen de aplicación subsidiaria. Las normas de esta Sección: a) se aplican en subsidio de las especiales que rigen para títulos valores determinados; b) no se aplican cuando leyes especiales así lo disponen, incluso en cuanto ellas se refieren a la obligatoriedad de alguna forma de creación o circulación de los", practicalEffects: ['En la práctica, este artículo rige aplicación subsidiaria. Las normas de esta Sección: a) se aplican en subsidio de las especiales que rigen para títulos valores determinados; b) no se aplican cuando leyes esp'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicacin', 'subsidiaria', 'articulo 1834'], segments: [], amendments: [] },
  { id: 'ccyc-art-1835', lawId: 'codigo-civil-comercial', number: '1835', order: 1835, title: "Títulos impropios y documentos de legitimación", text: "Títulos impropios y documentos de legitimación. Las disposiciones de este Capítulo no se aplican a los documentos, boletos, contraseñas, fichas u otros comprobantes que sirven exclusivamente para identificar a quien tiene derecho a exigir la prestación que en ellos se expresa o a que ellos dan lugar, o a permitir la transferencia del derecho sin la observancia de las formas propias de la cesión.", plainLanguageExplanation: "Establece el régimen de títulos impropios y documentos de legitimación. Las disposiciones de este Capítulo no se aplican a los documentos, boletos, contraseñas, fichas u otros comprobantes que sirven exclusivamente para identificar a quien tiene derecho a exigir la prestación que en ellos se expresa o a que ellos dan lugar, o a permitir la transferen", practicalEffects: ['En la práctica, este artículo rige títulos impropios y documentos de legitimación. Las disposiciones de este Capítulo no se aplican a los documentos, boletos, contraseñas, fichas u otros comprobantes que sirven exclusivamente para id'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ttulos', 'impropios', 'documentos', 'legitimacin', 'articulo 1835'], segments: [], amendments: [] },
  { id: 'ccyc-art-1836', lawId: 'codigo-civil-comercial', number: '1836', order: 1836, title: "Desmaterialización e ingreso en sistemas de anotaciones en cuenta", text: "Desmaterialización e ingreso en sistemas de anotaciones en cuenta. Los títulos valores tipificados legalmente como cartulares también pueden emitirse como no cartulares, para su ingreso y circulación en una caja de valores o un sistema autorizado de compensación bancaria o de anotaciones en cuenta. Los títulos valores emitidos efectivamente como cartulares pueden ingresarse a alguno de estos sistemas, conforme con sus reglamentos, momento a partir del cual las transferencias, gravámenes reales o personales y pago tienen efecto o se cumplen por las anotaciones en cuenta pertinentes. Parágrafo 1° Títulos valores al portador", plainLanguageExplanation: "Establece el régimen de desmaterialización e ingreso en sistemas de anotaciones en cuenta. Los títulos valores tipificados legalmente como cartulares también pueden emitirse como no cartulares, para su ingreso y circulación en una caja de valores o un sistema autorizado de compensación bancaria o de anotaciones en cuenta.", practicalEffects: ['En la práctica, este artículo rige desmaterialización e ingreso en sistemas de anotaciones en cuenta. Los títulos valores tipificados legalmente como cartulares también pueden emitirse como no cartulares, para su ingreso y circulación en una caja de va'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desmaterializacin', 'ingreso', 'sistemas', 'anotaciones', 'cuenta', 'articulo 1836'], segments: [], amendments: [] },
  { id: 'ccyc-art-1837', lawId: 'codigo-civil-comercial', number: '1837', order: 1837, title: "Concepto", text: "Concepto. Es título valor al portador, aunque no tenga cláusula expresa en tal sentido, aquel que no ha sido emitido en favor de sujeto determinado, o de otro modo indicada una ley de circulación diferente. La transferencia de un título valor al portador se produce con la tradición del título. Parágrafo 2° Títulos valores a la orden", plainLanguageExplanation: "Establece el régimen de concepto. Es título valor al portador, aunque no tenga cláusula expresa en tal sentido, aquel que no ha sido emitido en favor de sujeto determinado, o de otro modo indicada una ley de circulación diferente.", practicalEffects: ['En la práctica, este artículo rige concepto. Es título valor al portador, aunque no tenga cláusula expresa en tal sentido, aquel que no ha sido emitido en favor de sujeto determinado, o de otro modo indicada una ley de circulación diferente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 1837'], segments: [], amendments: [] },
  { id: 'ccyc-art-1838', lawId: 'codigo-civil-comercial', number: '1838', order: 1838, title: "Tipificación", text: "Tipificación. Es título valor a la orden el creado a favor de persona determinada. Sin necesidad de indicación especial, el título valor a la orden se transfiere mediante endoso. Si el creador del título valor incorpora la cláusula 'no a la orden' o equivalentes, la transferencia del título valor debe hacerse conforme con las reglas de la cesión de derechos, y tiene los efectos propios de la cesión.", plainLanguageExplanation: "Establece el régimen de tipificación. Es título valor a la orden el creado a favor de persona determinada.", practicalEffects: ['En la práctica, este artículo rige tipificación. Es título valor a la orden el creado a favor de persona determinada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tipificacinarticulo 1838'], segments: [], amendments: [] },
  { id: 'ccyc-art-1839', lawId: 'codigo-civil-comercial', number: '1839', order: 1839, title: "Endoso", text: "Endoso. El endoso debe constar en el título o en hoja de prolongación debidamente adherida e identificada y ser firmado por el endosante. Es válido el endoso aun sin mención del endosatario, o con la indicación 'al portador'. El endoso al portador tiene los efectos del endoso en blanco. El endoso puede hacerse al creador del título valor o a cualquier otro obligado, quienes pueden endosar nuevamente el título valor. En los fideicomisos financieros constituidos de conformidad con el artículo 1.690, que cuenten con autorización de oferta pública de sus títulos valores por parte del organismo de contralor de los mercados de valores, y cuyo activo subyacente se encuentre conformado por créditos instrumentados en títulos ejecutivos, se puede utilizar como mecanismo alternativo un endoso global, que debe ser otorgado por instrumento público y contener la identificación de los títulos endosados. (Artículo sustituido por art. 204 de la Ley N° 27.440 B.O. 11/5/2018)", plainLanguageExplanation: "Establece el régimen de endoso. El endoso debe constar en el título o en hoja de prolongación debidamente adherida e identificada y ser firmado por el endosante.", practicalEffects: ['En la práctica, este artículo rige endoso. El endoso debe constar en el título o en hoja de prolongación debidamente adherida e identificada y ser firmado por el endosante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['endosoarticulo 1839'], segments: [], amendments: [] },
  { id: 'ccyc-art-1840', lawId: 'codigo-civil-comercial', number: '1840', order: 1840, title: "Condición y endoso parcial", text: "Condición y endoso parcial. Cualquier condición puesta al endoso se tiene por no escrita. Es nulo el endoso parcial.", plainLanguageExplanation: "Establece el régimen de condición y endoso parcial. Cualquier condición puesta al endoso se tiene por no escrita.", practicalEffects: ['En la práctica, este artículo rige condición y endoso parcial. Cualquier condición puesta al endoso se tiene por no escrita.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condicin', 'endoso', 'parcial', 'articulo 1840'], segments: [], amendments: [] },
  { id: 'ccyc-art-1841', lawId: 'codigo-civil-comercial', number: '1841', order: 1841, title: "Tiempo del endoso", text: "Tiempo del endoso. El endoso puede ser efectuado en cualquier tiempo antes del vencimiento. El endoso sin fecha se presume efectuado antes del vencimiento. El endoso posterior al vencimiento produce los efectos de una cesión de derechos.", plainLanguageExplanation: "Establece el régimen de tiempo del endoso. El endoso puede ser efectuado en cualquier tiempo antes del vencimiento.", practicalEffects: ['En la práctica, este artículo rige tiempo del endoso. El endoso puede ser efectuado en cualquier tiempo antes del vencimiento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tiempo', 'endoso', 'articulo 1841'], segments: [], amendments: [] },
  { id: 'ccyc-art-1842', lawId: 'codigo-civil-comercial', number: '1842', order: 1842, title: "Legitimación", text: "Legitimación. El portador de un título a la orden queda legitimado para el ejercicio del derecho en él incorporado, por una serie no interrumpida de endosos formalmente válidos, aun cuando el último sea en blanco.", plainLanguageExplanation: "Establece el régimen de legitimación. El portador de un título a la orden queda legitimado para el ejercicio del derecho en él incorporado, por una serie no interrumpida de endosos formalmente válidos, aun cuando el último sea en blanco.", practicalEffects: ['En la práctica, este artículo rige legitimación. El portador de un título a la orden queda legitimado para el ejercicio del derecho en él incorporado, por una serie no interrumpida de endosos formalm'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimacinarticulo 1842'], segments: [], amendments: [] },
  { id: 'ccyc-art-1843', lawId: 'codigo-civil-comercial', number: '1843', order: 1843, title: "Endoso en blanco", text: "Endoso en blanco. Si el título es endosado en blanco, el portador puede llenar el endoso con su nombre o con el de otra persona, o endosar nuevamente el título, o transmitirlo a un tercero sin llenar el endoso o sin extender uno nuevo.", plainLanguageExplanation: "Establece el régimen de endoso en blanco. Si el título es endosado en blanco, el portador puede llenar el endoso con su nombre o con el de otra persona, o endosar nuevamente el título, o transmitirlo a un tercero sin llenar el endoso o sin extender uno nuevo.", practicalEffects: ['En la práctica, este artículo rige endoso en blanco. Si el título es endosado en blanco, el portador puede llenar el endoso con su nombre o con el de otra persona, o endosar nuevamente el título, o trans'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['endoso', 'blanco', 'articulo 1843'], segments: [], amendments: [] },
  { id: 'ccyc-art-1844', lawId: 'codigo-civil-comercial', number: '1844', order: 1844, title: "Endoso en procuración", text: "Endoso en procuración. Si el endoso contiene la cláusula 'en procuración' u otra similar, el endosatario puede ejercer, incluso judicialmente, todos los derechos inherentes al título valor, pero sólo puede endosarlo en procuración. Los obligados sólo pueden oponer al endosatario en procuración las excepciones que pueden ser opuestas al endosante. La eficacia del endoso en procuración no cesa por muerte o incapacidad sobrevenida del endosante.", plainLanguageExplanation: "Establece el régimen de endoso en procuración. Si el endoso contiene la cláusula 'en procuración' u otra similar, el endosatario puede ejercer, incluso judicialmente, todos los derechos inherentes al título valor, pero sólo puede endosarlo en procuración.", practicalEffects: ['En la práctica, este artículo rige endoso en procuración. Si el endoso contiene la cláusula \'en procuración\' u otra similar, el endosatario puede ejercer, incluso judicialmente, todos los derechos inherentes'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['endoso', 'procuracin', 'articulo 1844'], segments: [], amendments: [] },
  { id: 'ccyc-art-1845', lawId: 'codigo-civil-comercial', number: '1845', order: 1845, title: "Endoso en garantía", text: "Endoso en garantía. Si el endoso contiene la cláusula 'valor en prenda' u otra similar, el endosatario puede ejercer, incluso judicialmente, todos los derechos inherentes al título valor, pero el endoso hecho por él vale como endoso en procuración. El deudor demandado no puede invocar contra el portador las excepciones fundadas en sus relaciones con el endosante, a menos que el portador al recibir el título lo haya hecho a sabiendas en perjuicio de aquél.", plainLanguageExplanation: "Establece el régimen de endoso en garantía. Si el endoso contiene la cláusula 'valor en prenda' u otra similar, el endosatario puede ejercer, incluso judicialmente, todos los derechos inherentes al título valor, pero el endoso hecho por él vale como endoso en procuración.", practicalEffects: ['En la práctica, este artículo rige endoso en garantía. Si el endoso contiene la cláusula \'valor en prenda\' u otra similar, el endosatario puede ejercer, incluso judicialmente, todos los derechos inherentes'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['endoso', 'garanta', 'articulo 1845'], segments: [], amendments: [] },
  { id: 'ccyc-art-1846', lawId: 'codigo-civil-comercial', number: '1846', order: 1846, title: "Responsabilidad", text: "Responsabilidad. Excepto cláusula expresa, el endosante responde por el cumplimiento de la obligación incorporada. En cualquier caso, el endosante puede excluir total o parcialmente su responsabilidad mediante cláusula expresa. Parágrafo 3° Títulos valores nominativos endosables", plainLanguageExplanation: "Establece el régimen de responsabilidad. Excepto cláusula expresa, el endosante responde por el cumplimiento de la obligación incorporada.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. Excepto cláusula expresa, el endosante responde por el cumplimiento de la obligación incorporada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 1846'], segments: [], amendments: [] },
  { id: 'ccyc-art-1847', lawId: 'codigo-civil-comercial', number: '1847', order: 1847, title: "Régimen", text: "Régimen. Es título nominativo endosable el emitido en favor de una persona determinada, que sea transmisible por endoso y cuya transmisión produce efectos respecto al emisor y a terceros al inscribirse en el respectivo registro. El endosatario que justifica su derecho por una serie ininterrumpida de endosos está legitimado para solicitar la inscripción de su título. Si el emisor del título se niega a inscribir la transmisión, el endosatario puede reclamar la orden judicial correspondiente.", plainLanguageExplanation: "Establece el régimen de régimen. Es título nominativo endosable el emitido en favor de una persona determinada, que sea transmisible por endoso y cuya transmisión produce efectos respecto al emisor y a terceros al inscribirse en el respectivo registro.", practicalEffects: ['En la práctica, este artículo rige régimen. Es título nominativo endosable el emitido en favor de una persona determinada, que sea transmisible por endoso y cuya transmisión produce efectos resp'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rgimenarticulo 1847'], segments: [], amendments: [] },
  { id: 'ccyc-art-1848', lawId: 'codigo-civil-comercial', number: '1848', order: 1848, title: "Reglas aplicables", text: "Reglas aplicables. Son aplicables a los títulos nominativos endosables las disposiciones compatibles de los títulos valores a la orden. Parágrafo 4° Títulos valores nominativos no endosables", plainLanguageExplanation: "Establece el régimen de reglas aplicables. Son aplicables a los títulos nominativos endosables las disposiciones compatibles de los títulos valores a la orden.", practicalEffects: ['En la práctica, este artículo rige reglas aplicables. Son aplicables a los títulos nominativos endosables las disposiciones compatibles de los títulos valores a la orden.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'aplicables', 'articulo 1848'], segments: [], amendments: [] },
  { id: 'ccyc-art-1849', lawId: 'codigo-civil-comercial', number: '1849', order: 1849, title: "Régimen", text: "Régimen. Es título valor nominativo no endosable el emitido a favor de una persona determinada, y cuya transmisión produce efectos respecto al emisor y a terceros al inscribirse en el respectivo registro. SECCION 3ª Títulos valores no cartulares", plainLanguageExplanation: "Establece el régimen de régimen. Es título valor nominativo no endosable el emitido a favor de una persona determinada, y cuya transmisión produce efectos respecto al emisor y a terceros al inscribirse en el respectivo registro.", practicalEffects: ['En la práctica, este artículo rige régimen. Es título valor nominativo no endosable el emitido a favor de una persona determinada, y cuya transmisión produce efectos respecto al emisor y a terceros al inscribirse en el respectivo registro.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rgimenarticulo 1849'], segments: [], amendments: [] },
  { id: 'ccyc-art-1850', lawId: 'codigo-civil-comercial', number: '1850', order: 1850, title: "Régimen", text: "Régimen. Cuando por disposición legal o cuando en el instrumento de creación se inserta una declaración expresa de voluntad de obligarse de manera incondicional e irrevocable, aunque la prestación no se incorpore a un documento, puede establecerse la circulación autónoma del derecho, con sujeción a lo dispuesto en el artículo 1820. La transmisión o constitución de derechos reales sobre el título valor, los gravámenes, secuestros, medidas precautorias y cualquier otra afectación de los derechos conferidos por el título valor deben efectuarse mediante asientos en registros especiales que debe llevar el emisor o, en nombre de éste, una caja de valores, una entidad financiera autorizada o un escribano de registro, momento a partir del cual la afectación produce efectos frente a terceros. A los efectos de determinar el alcance de los derechos emergentes del título valor así creado debe estarse al instrumento de creación, que debe tener fecha cierta. Si el título valor es admitido a la oferta pública es suficiente su inscripción ante la autoridad de contralor y en las bolsas o mercados en los que se negocia. Se aplica respecto del tercero que adquiera el título valor lo dispuesto por los artículos 1816 y 1819.", plainLanguageExplanation: "Establece el régimen de régimen. Cuando por disposición legal o cuando en el instrumento de creación se inserta una declaración expresa de voluntad de obligarse de manera incondicional e irrevocable, aunque la prestación no se incorpore a un documento, puede establecerse la circulación autónoma del derecho, con", practicalEffects: ['En la práctica, este artículo rige régimen. Cuando por disposición legal o cuando en el instrumento de creación se inserta una declaración expresa de voluntad de obligarse de manera incondiciona'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rgimenarticulo 1850'], segments: [], amendments: [] },
  { id: 'ccyc-art-1851', lawId: 'codigo-civil-comercial', number: '1851', order: 1851, title: "Comprobantes de saldos", text: "Comprobantes de saldos. La entidad que lleve el registro debe expedir comprobantes de saldos de cuentas, a efectos de: a) legitimar al titular para reclamar judicialmente, incluso mediante acción ejecutiva si corresponde, o ante jurisdicción arbitral en su caso, presentar solicitudes de verificación de crédito o participar en procesos universales para lo que es suficiente título dicho comprobante, sin necesidad de autenticación u otro requisito. Su expedición importa el bloqueo de la cuenta respectiva, sólo para inscribir actos de disposición por su titular, por un plazo de treinta días, excepto que el titular devuelva el comprobante o dentro de dicho plazo se reciba una orden de prórroga del bloqueo del juez o tribunal arbitral ante el cual el comprobante se hizo valer. Los comprobantes deben mencionar estas circunstancias; b) asistir a asambleas u otros actos vinculados al régimen de los títulos valores. La expedición de comprobantes del saldo de cuenta para la asistencia a asambleas o el ejercicio de derechos de voto importa el bloqueo de la cuenta respectiva hasta el día siguiente al fijado para la celebración de la asamblea correspondiente. Si la asamblea pasa a cuarto intermedio o se reúne en otra oportunidad, se requiere la expedición de nuevos comprobantes pero éstos sólo pueden expedirse a nombre de las mismas personas que fueron legitimadas mediante la expedición de los comprobantes originales; c) los fines que estime necesario el titular a su pedido. En los casos de los incisos a) y b) no puede extenderse un comprobante mientras está vigente otro expedido para la misma finalidad. Se pueden expedir comprobantes de los títulos valores representados en certificados globales a favor de las personas que tengan una participación en los mismos, a los efectos y con el alcance indicados en el inciso a). El bloqueo de la cuenta sólo afecta a los títulos valores a los que refiere el comprobante. Los comprobantes son emitidos por la entidad del país o del exterior que administre el sistema de depósito colectivo en el cual se encuentran inscriptos los certificados globales. Cuando entidades administradoras de sistemas de depósito colectivo tienen participaciones en certificados globales inscriptos en sistemas de depósito colectivo administrados por otra entidad, los comprobantes pueden ser emitidos directamente por las primeras. En todos los casos, los gastos son a cargo del solicitante. SECCION 4ª Deterioro, sustracción, pérdida y destrucción de títulos valores o de sus registros Parágrafo 1° Normas comunes para títulos valores", plainLanguageExplanation: "Establece el régimen de comprobantes de saldos. La entidad que lleve el registro debe expedir comprobantes de saldos de cuentas, a efectos de: a) legitimar al titular para reclamar judicialmente, incluso mediante acción ejecutiva si corresponde, o ante jurisdicción arbitral en su caso, presentar solicitudes de verificación de", practicalEffects: ['En la práctica, este artículo rige comprobantes de saldos. La entidad que lleve el registro debe expedir comprobantes de saldos de cuentas, a efectos de: a) legitimar al titular para reclamar judicialmente, in'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comprobantes', 'saldos', 'articulo 1851'], segments: [], amendments: [] },
  { id: 'ccyc-art-1852', lawId: 'codigo-civil-comercial', number: '1852', order: 1852, title: "Ambito de aplicación", text: "Ambito de aplicación. Jurisdicción. Las disposiciones de esta Sección se aplican en caso de sustracción, pérdida o destrucción de títulos valores incorporados a documentos representativos, en tanto no existan normas especiales para tipos determinados de ellos. El procedimiento se lleva a cabo en jurisdicción del domicilio del creador, en los títulos valores en serie; o en la del lugar de pago, en los títulos valores individuales. Los gastos son a cargo del solicitante. La cancelación del título valor no perjudica los derechos de quien no formula oposición respecto de quien obtiene la cancelación. En los supuestos en que la sentencia que ordena la cancelación queda firme, el juez puede exigir que el solicitante preste caución en resguardo de los derechos del adquirente del título valor cancelado, por un plazo no superior a dos años.", plainLanguageExplanation: "Establece el régimen de ambito de aplicación. Jurisdicción.", practicalEffects: ['En la práctica, este artículo rige ambito de aplicación. Jurisdicción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ambito', 'aplicacin', 'articulo 1852'], segments: [], amendments: [] },
  { id: 'ccyc-art-1853', lawId: 'codigo-civil-comercial', number: '1853', order: 1853, title: "Sustitución por deterioro", text: "Sustitución por deterioro. El portador de un título valor deteriorado, pero identificable con certeza, tiene derecho a obtener del emisor un duplicado si restituye el original y reembolsa los gastos. Los firmantes del título valor original están obligados a reproducir su firma en el duplicado.", plainLanguageExplanation: "Establece el régimen de sustitución por deterioro. El portador de un título valor deteriorado, pero identificable con certeza, tiene derecho a obtener del emisor un duplicado si restituye el original y reembolsa los gastos.", practicalEffects: ['En la práctica, este artículo rige sustitución por deterioro. El portador de un título valor deteriorado, pero identificable con certeza, tiene derecho a obtener del emisor un duplicado si restituye el original y reembolsa los gastos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sustitucin', 'deterioro', 'articulo 1853'], segments: [], amendments: [] },
  { id: 'ccyc-art-1854', lawId: 'codigo-civil-comercial', number: '1854', order: 1854, title: "Obligaciones de terceros", text: "Obligaciones de terceros. Si los títulos valores instrumentaban obligaciones de otras personas, además de las del emisor, deben reproducirlas en los nuevos títulos. Igualmente debe efectuarse una atestación notarial de correlación. Cuando los terceros se oponen a reproducir instrumentalmente sus obligaciones, debe resolver el juez por el procedimiento contradictorio más breve que prevea la ley local, sin perjuicio del otorgamiento de los títulos valores provisorios o definitivos, cuando corresponda. Parágrafo 2° Normas aplicables a títulos valores en serie", plainLanguageExplanation: "Establece el régimen de obligaciones de terceros. Si los títulos valores instrumentaban obligaciones de otras personas, además de las del emisor, deben reproducirlas en los nuevos títulos.", practicalEffects: ['En la práctica, este artículo rige obligaciones de terceros. Si los títulos valores instrumentaban obligaciones de otras personas, además de las del emisor, deben reproducirlas en los nuevos títulos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'terceros', 'articulo 1854'], segments: [], amendments: [] },
  { id: 'ccyc-art-1855', lawId: 'codigo-civil-comercial', number: '1855', order: 1855, title: "Denuncia", text: "Denuncia. En los casos previstos en el artículo 1852 el titular o portador legítimo debe denunciar el hecho al emisor mediante escritura pública o, tratándose de títulos ofertados públicamente, por nota con firma certificada por notario o presentada personalmente ante la autoridad pública de control, una entidad en que se negocien los títulos valores o el Banco Central de la República Argentina, si es el emisor. Debe acompañar una suma suficiente, a criterio del emisor, para satisfacer los gastos de publicación y correspondencia. La denuncia debe contener: a) la individualización de los títulos valores, indicando, en su caso, denominación, valor nominal, serie y numeración; b) la manera como adquirió la titularidad, posesión o tenencia de los títulos y la época y, de ser posible, la fecha de los actos respectivos; c) fecha, forma y lugar de percepción del último dividendo, interés, cuota de amortización o del ejercicio de los derechos emergentes del título; d) enunciación de las circunstancias que causaron la pérdida, sustracción o destrucción. Si la destrucción fuera parcial, debe exhibir los restos de los títulos valores en su poder; e) constitución de domicilio especial en la jurisdicción donde tuviera la sede el emisor o, en su caso, en el lugar de pago.", plainLanguageExplanation: "Establece el régimen de denuncia. En los casos previstos en el artículo 1852 el titular o portador legítimo debe denunciar el hecho al emisor mediante escritura pública o, tratándose de títulos ofertados públicamente, por nota con firma certificada por notario o presentada personalmente ante la autoridad pública", practicalEffects: ['En la práctica, este artículo rige denuncia. En los casos previstos en el artículo 1852 el titular o portador legítimo debe denunciar el hecho al emisor mediante escritura pública o, tratándose d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['denunciaarticulo 1855'], segments: [], amendments: [] },
  { id: 'ccyc-art-1856', lawId: 'codigo-civil-comercial', number: '1856', order: 1856, title: "Suspensión de efectos", text: "Suspensión de efectos. El emisor debe suspender de inmediato los efectos de los títulos con respecto a terceros, bajo responsabilidad del peticionante, y entregar al denunciante constancia de su presentación y de la suspensión dispuesta. Igual suspensión debe disponer, en caso de títulos valores ofertados públicamente, la entidad ante quien se presente la denuncia.", plainLanguageExplanation: "Establece el régimen de suspensión de efectos. El emisor debe suspender de inmediato los efectos de los títulos con respecto a terceros, bajo responsabilidad del peticionante, y entregar al denunciante constancia de su presentación y de la suspensión dispuesta.", practicalEffects: ['En la práctica, este artículo rige suspensión de efectos. El emisor debe suspender de inmediato los efectos de los títulos con respecto a terceros, bajo responsabilidad del peticionante, y entregar al denunci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensin', 'efectos', 'articulo 1856'], segments: [], amendments: [] },
  { id: 'ccyc-art-1857', lawId: 'codigo-civil-comercial', number: '1857', order: 1857, title: "Publicación", text: "Publicación. El emisor debe publicar en el Boletín Oficial y en uno de los diarios de mayor circulación en la República, por un día, un aviso que debe contener el nombre, documento de identidad y domicilio especial del denunciante, así como los datos necesarios para la identificación de los títulos valores comprendidos, e incluir la especie, numeración, valor nominal y cupón corriente de los títulos, en su caso y la citación a quienes se crean con derecho a ellos para que deduzcan oposición, dentro de los sesenta días. Las publicaciones deben ser diligenciadas por el emisor dentro del día hábil siguiente a la presentación de la denuncia.", plainLanguageExplanation: "Establece el régimen de publicación. El emisor debe publicar en el Boletín Oficial y en uno de los diarios de mayor circulación en la República, por un día, un aviso que debe contener el nombre, documento de identidad y domicilio especial del denunciante, así como los datos necesarios para la identificación de los t", practicalEffects: ['En la práctica, este artículo rige publicación. El emisor debe publicar en el Boletín Oficial y en uno de los diarios de mayor circulación en la República, por un día, un aviso que debe contener el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicacinarticulo 1857'], segments: [], amendments: [] },
  { id: 'ccyc-art-1858', lawId: 'codigo-civil-comercial', number: '1858', order: 1858, title: "Títulos con cotización pública", text: "Títulos con cotización pública. Cuando los títulos valores cotizan públicamente, además de las publicaciones mencionadas en el artículo 1857, el emisor o la entidad que recibe la denuncia, está obligado a comunicarla a la entidad en la que coticen más cercana a su domicilio y, en su caso, al emisor en el mismo día de su recepción. La entidad debe hacer saber la denuncia, en igual plazo, al órgano de contralor de los mercados de valores, a las cajas de valores, y a las restantes entidades expresamente autorizadas por la ley especial o la autoridad de aplicación en que coticen los títulos valores. Las entidades expresamente autorizadas por la ley especial o la autoridad de aplicación en que se negocian los títulos valores, deben publicar un aviso en su órgano informativo o hacerlo saber por otros medios adecuados, dentro del mismo día de recibida la denuncia o la comunicación pertinente. Las entidades expresamente autorizadas por la ley especial o la autoridad de aplicación deben llevar un registro para consulta de los interesados, con la nómina de los títulos valores que hayan sido objeto de denuncia.", plainLanguageExplanation: "Establece el régimen de títulos con cotización pública. Cuando los títulos valores cotizan públicamente, además de las publicaciones mencionadas en el artículo 1857, el emisor o la entidad que recibe la denuncia, está obligado a comunicarla a la entidad en la que coticen más cercana a su domicilio y, en su caso, al emisor en el mismo día de su recepción.", practicalEffects: ['En la práctica, este artículo rige títulos con cotización pública. Cuando los títulos valores cotizan públicamente, además de las publicaciones mencionadas en el artículo 1857, el emisor o la entidad que recibe la den'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ttulos', 'cotizacin', 'pblica', 'articulo 1858'], segments: [], amendments: [] },
  { id: 'ccyc-art-1859', lawId: 'codigo-civil-comercial', number: '1859', order: 1859, title: "Partes interesadas", text: "Partes interesadas. El denunciante debe indicar, en su caso, el nombre y domicilio de la persona por quien posee o por quien tiene en su poder el título valor, así como en su caso el de los usufructuarios y el de los acreedores prendarios de aquél. El emisor debe citar por medio fehaciente a las personas indicadas por el denunciante o las que figuran con tales calidades en el respectivo registro, en los domicilios denunciados o registrados, a los fines del artículo 1857. La ausencia de denuncia o citación no invalida el procedimiento, sin perjuicio de las responsabilidades consiguientes.", plainLanguageExplanation: "Establece el régimen de partes interesadas. El denunciante debe indicar, en su caso, el nombre y domicilio de la persona por quien posee o por quien tiene en su poder el título valor, así como en su caso el de los usufructuarios y el de los acreedores prendarios de aquél.", practicalEffects: ['En la práctica, este artículo rige partes interesadas. El denunciante debe indicar, en su caso, el nombre y domicilio de la persona por quien posee o por quien tiene en su poder el título valor, así como e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['partes', 'interesadas', 'articulo 1859'], segments: [], amendments: [] },
  { id: 'ccyc-art-1860', lawId: 'codigo-civil-comercial', number: '1860', order: 1860, title: "Observaciones", text: "Observaciones. El emisor debe expresar al denunciante dentro de los diez días las observaciones que tiene sobre el contenido de la denuncia o su verosimilitud.", plainLanguageExplanation: "Establece el régimen de observaciones. El emisor debe expresar al denunciante dentro de los diez días las observaciones que tiene sobre el contenido de la denuncia o su verosimilitud.", practicalEffects: ['En la práctica, este artículo rige observaciones. El emisor debe expresar al denunciante dentro de los diez días las observaciones que tiene sobre el contenido de la denuncia o su verosimilitud.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['observacionesarticulo 1860'], segments: [], amendments: [] },
  { id: 'ccyc-art-1861', lawId: 'codigo-civil-comercial', number: '1861', order: 1861, title: "Certificado provisorio", text: "Certificado provisorio. Pasados sesenta días desde la última publicación indicada en el artículo 1857, el emisor debe extender un certificado provisorio no negociable, excepto que se presente alguna de las siguientes circunstancias: a) que a su criterio no se hayan subsanado las observaciones indicadas; b) que se hayan presentado uno o más contradictores dentro del plazo; c) que exista orden judicial en contrario; d) que se haya aplicado lo dispuesto en los artículos 1866 y 1867.", plainLanguageExplanation: "Establece el régimen de certificado provisorio. Pasados sesenta días desde la última publicación indicada en el artículo 1857, el emisor debe extender un certificado provisorio no negociable, excepto que se presente alguna de las siguientes circunstancias: a) que a su criterio no se hayan subsanado las observaciones indicadas;", practicalEffects: ['En la práctica, este artículo rige certificado provisorio. Pasados sesenta días desde la última publicación indicada en el artículo 1857, el emisor debe extender un certificado provisorio no negociable, except'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['certificado', 'provisorio', 'articulo 1861'], segments: [], amendments: [] },
  { id: 'ccyc-art-1862', lawId: 'codigo-civil-comercial', number: '1862', order: 1862, title: "Denegación", text: "Denegación. Acciones. Denegada la expedición del certificado provisorio, el emisor debe hacerlo saber por medio fehaciente al denunciante. Este tiene expedita la acción ante el juez del domicilio del emisor para que le sea extendido el certificado o por reivindicación o, en el caso del inciso d) del artículo 1861, por los daños que correspondan.", plainLanguageExplanation: "Establece el régimen de denegación. Acciones.", practicalEffects: ['En la práctica, este artículo rige denegación. Acciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['denegacinarticulo 1862'], segments: [], amendments: [] },
  { id: 'ccyc-art-1863', lawId: 'codigo-civil-comercial', number: '1863', order: 1863, title: "Depósito o entrega de las prestaciones", text: "Depósito o entrega de las prestaciones. Las prestaciones dinerarias correspondientes al certificado provisorio deben ser depositadas por el emisor, a su vencimiento, en el banco oficial de su domicilio. El denunciante puede indicar, en cada oportunidad, la modalidad de inversión de su conveniencia, entre las ofrecidas por el banco oficial. En su defecto, el emisor la determina entre las corrientes en plaza, sin responsabilidad. A pedido del denunciante y previa constitución de garantía suficiente, a juicio del emisor, éste puede entregarle las acreencias dinerarias a su vencimiento, o posteriormente desafectándolas del depósito, con conformidad del peticionario. La garantía se mantiene, bajo responsabilidad del emisor, durante el plazo previsto en el artículo 1865, excepto orden judicial en contrario. Si no existe acuerdo sobre la suficiencia de la garantía, resuelve el juez con competencia en el domicilio del emisor, por el procedimiento más breve previsto por la legislación local.", plainLanguageExplanation: "Establece el régimen de depósito o entrega de las prestaciones. Las prestaciones dinerarias correspondientes al certificado provisorio deben ser depositadas por el emisor, a su vencimiento, en el banco oficial de su domicilio.", practicalEffects: ['En la práctica, este artículo rige depósito o entrega de las prestaciones. Las prestaciones dinerarias correspondientes al certificado provisorio deben ser depositadas por el emisor, a su vencimiento, en el banco oficial de su domicilio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['depsito', 'entrega', 'prestaciones', 'articulo 1863'], segments: [], amendments: [] },
  { id: 'ccyc-art-1864', lawId: 'codigo-civil-comercial', number: '1864', order: 1864, title: "Ejercicio de derechos de contenido no dinerario", text: "Ejercicio de derechos de contenido no dinerario. Si el título valor otorga derechos de contenido no dinerarios, sin perjuicio del cumplimiento de los demás procedimientos establecidos, el juez puede autorizar, bajo la caución que estime apropiada, el ejercicio de esos derechos y la recepción de las prestaciones pertinentes. Respecto de las prestaciones dinerarias, se aplican las normas comunes de esta Sección.", plainLanguageExplanation: "Establece el régimen de ejercicio de derechos de contenido no dinerario. Si el título valor otorga derechos de contenido no dinerarios, sin perjuicio del cumplimiento de los demás procedimientos establecidos, el juez puede autorizar, bajo la caución que estime apropiada, el ejercicio de esos derechos y la recepción de las prestaciones pertinentes.", practicalEffects: ['En la práctica, este artículo rige ejercicio de derechos de contenido no dinerario. Si el título valor otorga derechos de contenido no dinerarios, sin perjuicio del cumplimiento de los demás procedimientos establecidos, el juez puede'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejercicio', 'derechos', 'contenido', 'dinerario', 'articulo 1864'], segments: [], amendments: [] },
  { id: 'ccyc-art-1865', lawId: 'codigo-civil-comercial', number: '1865', order: 1865, title: "Títulos valores definitivos", text: "Títulos valores definitivos. Transcurrido un año desde la entrega del certificado provisorio, el emisor lo debe canjear por un nuevo título definitivo, a todos los efectos legales, previa cancelación del original, excepto que medie orden judicial en contrario. El derecho a solicitar conversión de los títulos valores cancelados se suspende mientras esté vigente el certificado provisorio.", plainLanguageExplanation: "Establece el régimen de títulos valores definitivos. Transcurrido un año desde la entrega del certificado provisorio, el emisor lo debe canjear por un nuevo título definitivo, a todos los efectos legales, previa cancelación del original, excepto que medie orden judicial en contrario.", practicalEffects: ['En la práctica, este artículo rige títulos valores definitivos. Transcurrido un año desde la entrega del certificado provisorio, el emisor lo debe canjear por un nuevo título definitivo, a todos los efectos legales'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ttulos', 'valores', 'definitivos', 'articulo 1865'], segments: [], amendments: [] },
  { id: 'ccyc-art-1866', lawId: 'codigo-civil-comercial', number: '1866', order: 1866, title: "Presentación del portador", text: "Presentación del portador. Si dentro del plazo establecido en el artículo 1865 se presenta un tercero con el título valor en su poder, adquirido conforme con su ley de circulación, el emisor debe hacerlo saber de inmediato en forma fehaciente al denunciante. Los efectos que prevé el artículo 1865, así como los del artículo 1863, segundo y tercer párrafos, quedan en suspenso desde la presentación hasta que el juez competente se pronuncie. El denunciante debe iniciar la acción judicial dentro de los dos meses de la notificación por el emisor; caso contrario, caduca su derecho respecto del título valor.", plainLanguageExplanation: "Establece el régimen de presentación del portador. Si dentro del plazo establecido en el artículo 1865 se presenta un tercero con el título valor en su poder, adquirido conforme con su ley de circulación, el emisor debe hacerlo saber de inmediato en forma fehaciente al denunciante.", practicalEffects: ['En la práctica, este artículo rige presentación del portador. Si dentro del plazo establecido en el artículo 1865 se presenta un tercero con el título valor en su poder, adquirido conforme con su ley de circulaci'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presentacin', 'portador', 'articulo 1866'], segments: [], amendments: [] },
  { id: 'ccyc-art-1867', lawId: 'codigo-civil-comercial', number: '1867', order: 1867, title: "Adquirente en bolsa o caja de valores", text: "Adquirente en bolsa o caja de valores. El tercer portador que haya adquirido el título valor sin culpa grave, que se oponga dentro del plazo del artículo 1865 y acredite que, con anterioridad a la primera publicación del artículo 1857 o a la publicación por el órgano informativo u otros medios adecuados en la entidad expresamente autorizada por la ley especial o la autoridad de aplicación en que coticen los títulos valores, lo que ocurra primero, adquirió el título valor en una entidad así autorizada, aun cuando le haya sido entregado con posterioridad a las publicaciones o comunicaciones, puede reclamar directamente del emisor: a) el levantamiento de la suspensión de los efectos de los títulos valores; b) la cancelación del certificado provisorio que se haya entregado al denunciante; c) la entrega de las acreencias que hayan sido depositadas conforme al artículo 1863. La adquisición o tenencia en los supuestos indicados impide el ejercicio de la acción reivindicatoria por el denunciante, y deja a salvo la acción por daños contra quienes, por su dolo o culpa, han hecho posible o contribuido a la pérdida de su derecho.", plainLanguageExplanation: "Establece el régimen de adquirente en bolsa o caja de valores. El tercer portador que haya adquirido el título valor sin culpa grave, que se oponga dentro del plazo del artículo 1865 y acredite que, con anterioridad a la primera publicación del artículo 1857 o a la publicación por el órgano informativo u otros medios adecuados en la entidad", practicalEffects: ['En la práctica, este artículo rige adquirente en bolsa o caja de valores. El tercer portador que haya adquirido el título valor sin culpa grave, que se oponga dentro del plazo del artículo 1865 y acredite que, con anteriorid'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['adquirente', 'bolsa', 'caja', 'valores', 'articulo 1867'], segments: [], amendments: [] },
  { id: 'ccyc-art-1868', lawId: 'codigo-civil-comercial', number: '1868', order: 1868, title: "Desestimación de oposición", text: "Desestimación de oposición. Debe desestimarse sin más trámite toda oposición planteada contra una caja de valores respecto del título valor recibido de buena fe, cuyo depósito colectivo se haya perfeccionado antes de recibir dicha caja la comunicación de la denuncia que prevé el artículo 1855, y a más tardar o en defecto de esa comunicación, hasta la publicación del aviso que establece el artículo 1857. Ello, sin perjuicio de los derechos del oponente sobre la cuotaparte de títulos valores de igual especie, clase y emisor que corresponda al comitente responsable. También debe desestimarse sin más trámite toda oposición planteada contra un depositante autorizado, respecto del título valor recibido de buena fe para ingresarlo en depósito colectivo en una caja de valores antes de las publicaciones que prevén los artículos 1855, 1857 y 1858, sin perjuicio de los derechos del oponente mencionados en el párrafo anterior. En caso de destrucción total o parcial de un título valor depositado, la caja de valores queda obligada a cumplir con las disposiciones de esta Sección.", plainLanguageExplanation: "Establece el régimen de desestimación de oposición. Debe desestimarse sin más trámite toda oposición planteada contra una caja de valores respecto del título valor recibido de buena fe, cuyo depósito colectivo se haya perfeccionado antes de recibir dicha caja la comunicación de la denuncia que prevé el artículo 1855, y a más tarda", practicalEffects: ['En la práctica, este artículo rige desestimación de oposición. Debe desestimarse sin más trámite toda oposición planteada contra una caja de valores respecto del título valor recibido de buena fe, cuyo depósito co'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desestimacin', 'oposicin', 'articulo 1868'], segments: [], amendments: [] },
  { id: 'ccyc-art-1869', lawId: 'codigo-civil-comercial', number: '1869', order: 1869, title: "Títulos valores nominativos no endosables", text: "Títulos valores nominativos no endosables. Si se trata de título valor nominativo no endosable, dándose las condiciones previstas en el artículo 1861, el emisor debe extender directamente un nuevo título valor definitivo a nombre del titular registrado y dejar constancia de los gravámenes existentes. En el caso, no corresponde la aplicación de los artículos 1864 y 1865.", plainLanguageExplanation: "Establece el régimen de títulos valores nominativos no endosables. Si se trata de título valor nominativo no endosable, dándose las condiciones previstas en el artículo 1861, el emisor debe extender directamente un nuevo título valor definitivo a nombre del titular registrado y dejar constancia de los gravámenes existentes.", practicalEffects: ['En la práctica, este artículo rige títulos valores nominativos no endosables. Si se trata de título valor nominativo no endosable, dándose las condiciones previstas en el artículo 1861, el emisor debe extender directamente un nu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ttulos', 'valores', 'nominativos', 'endosables', 'articulo 1869'], segments: [], amendments: [] },
  { id: 'ccyc-art-1870', lawId: 'codigo-civil-comercial', number: '1870', order: 1870, title: "Cupones separables", text: "Cupones separables. El procedimiento comprende los cupones separables vinculados con el título valor, en tanto no haya comenzado su período de utilización al efectuarse la primera publicación. Los cupones separables en período de utilización, deben someterse al procedimiento que corresponda según su ley de circulación. Parágrafo 3° Normas aplicables a los títulos valores individuales", plainLanguageExplanation: "Establece el régimen de cupones separables. El procedimiento comprende los cupones separables vinculados con el título valor, en tanto no haya comenzado su período de utilización al efectuarse la primera publicación.", practicalEffects: ['En la práctica, este artículo rige cupones separables. El procedimiento comprende los cupones separables vinculados con el título valor, en tanto no haya comenzado su período de utilización al efectuarse la primera publicación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cupones', 'separables', 'articulo 1870'], segments: [], amendments: [] },
  { id: 'ccyc-art-1871', lawId: 'codigo-civil-comercial', number: '1871', order: 1871, title: "Denuncia", text: "Denuncia. El último portador debe denunciar judicialmente el hecho, y solicitar la cancelación de los títulos valores. La demanda debe contener: a) la individualización precisa de los títulos valores cuya desposesión se denuncia; b) las circunstancias en las cuales el título valor fue adquirido por el denunciante, precisando la fecha o época de su adquisición; c) la indicación de las prestaciones percibidas por el denunciante, y las pendientes de percepción, devengadas o no; d) las circunstancias que causaron la pérdida, sustracción o destrucción. En todos los casos, el solicitante puede realizar actos conservatorios de sus derechos.", plainLanguageExplanation: "Establece el régimen de denuncia. El último portador debe denunciar judicialmente el hecho, y solicitar la cancelación de los títulos valores.", practicalEffects: ['En la práctica, este artículo rige denuncia. El último portador debe denunciar judicialmente el hecho, y solicitar la cancelación de los títulos valores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['denunciaarticulo 1871'], segments: [], amendments: [] },
  { id: 'ccyc-art-1872', lawId: 'codigo-civil-comercial', number: '1872', order: 1872, title: "Notificación", text: "Notificación. Hecha la presentación a que se refiere el artículo 1871, y si los datos aportados resultan en principio verosímiles, el juez debe ordenar la notificación de la sustracción, pérdida o destrucción al creador del título valor y a los demás firmantes obligados al pago, disponiendo su cancelación y autorizando el pago de las prestaciones exigibles después de los treinta días de cumplida la publicación prevista en el artículo siguiente, si no se deduce oposición.", plainLanguageExplanation: "Establece el régimen de notificación. Hecha la presentación a que se refiere el artículo 1871, y si los datos aportados resultan en principio verosímiles, el juez debe ordenar la notificación de la sustracción, pérdida o destrucción al creador del título valor y a los demás firmantes obligados al pago, disponiendo su", practicalEffects: ['En la práctica, este artículo rige notificación. Hecha la presentación a que se refiere el artículo 1871, y si los datos aportados resultan en principio verosímiles, el juez debe ordenar la notificac'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['notificacinarticulo 1872'], segments: [], amendments: [] },
  { id: 'ccyc-art-1873', lawId: 'codigo-civil-comercial', number: '1873', order: 1873, title: "Publicación", text: "Publicación. Pago anterior. La resolución judicial prevista en el artículo 1872 debe ordenar, además, la publicación de un edicto por un día en el Boletín Oficial y en uno de los diarios de mayor circulación del lugar del procedimiento, que debe contener: a) los datos del denunciante y la identificación del título valor cuya desposesión fue denunciada; b) la citación para que los interesados deduzcan oposición al procedimiento, la que debe formularse dentro de los treinta días de la publicación. El pago hecho antes de la publicación es liberatorio si es efectuado sin dolo ni culpa.", plainLanguageExplanation: "Establece el régimen de publicación. Pago anterior.", practicalEffects: ['En la práctica, este artículo rige publicación. Pago anterior.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicacinarticulo 1873'], segments: [], amendments: [] },
  { id: 'ccyc-art-1874', lawId: 'codigo-civil-comercial', number: '1874', order: 1874, title: "Duplicado", text: "Duplicado. Cumplimiento. Transcurridos treinta días sin que se formule oposición, el solicitante tiene derecho a obtener un duplicado del título valor, si la prestación no es exigible; o a reclamar el cumplimiento de la prestación exigible, con el testimonio de la sentencia firme de cancelación. El solicitante tiene el mismo derecho cuando la oposición es desestimada.", plainLanguageExplanation: "Establece el régimen de duplicado. Cumplimiento.", practicalEffects: ['En la práctica, este artículo rige duplicado. Cumplimiento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['duplicadoarticulo 1874'], segments: [], amendments: [] },
  { id: 'ccyc-art-1875', lawId: 'codigo-civil-comercial', number: '1875', order: 1875, title: "Oposición", text: "Oposición. La oposición tramita por el procedimiento más breve previsto en la ley local. El oponente debe depositar el título valor ante el juez interviniente al deducir la oposición, que le debe ser restituido si es admitida. Si es rechazada, el título valor se debe entregar a quien obtuvo la sentencia de cancelación. Parágrafo 4° Sustracción, pérdida o destrucción de los libros de registro", plainLanguageExplanation: "Establece el régimen de oposición. La oposición tramita por el procedimiento más breve previsto en la ley local.", practicalEffects: ['En la práctica, este artículo rige oposición. La oposición tramita por el procedimiento más breve previsto en la ley local.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oposicinarticulo 1875'], segments: [], amendments: [] },
  { id: 'ccyc-art-1876', lawId: 'codigo-civil-comercial', number: '1876', order: 1876, title: "Denuncia", text: "Denuncia. Si se trata de títulos valores nominativos o títulos valores no cartulares, incluso los ingresados a sistemas de anotaciones en cuenta según el artículo 1836, la sustracción, pérdida o destrucción del libro de registro respectivo, incluso cuando son llevados por ordenadores, medios mecánicos o magnéticos u otros, debe ser denunciada por el emisor o por quien lo lleva en su nombre, dentro de las veinticuatro horas de conocido el hecho. La denuncia debe efectuarse ante el juez del domicilio del emisor, con indicación de los elementos necesarios para juzgarla y contener los datos que puede aportar el denunciante sobre las constancias que incluía el libro. Copias de la denuncia deben ser presentadas en igual término al organismo de contralor societario, al organismo de contralor de los mercados de valores y a las entidades expresamente autorizadas por la ley especial o la autoridad de aplicación y cajas de valores respectivos, en su caso.", plainLanguageExplanation: "Establece el régimen de denuncia. Si se trata de títulos valores nominativos o títulos valores no cartulares, incluso los ingresados a sistemas de anotaciones en cuenta según el artículo 1836, la sustracción, pérdida o destrucción del libro de registro respectivo, incluso cuando son llevados por ordenadores, medi", practicalEffects: ['En la práctica, este artículo rige denuncia. Si se trata de títulos valores nominativos o títulos valores no cartulares, incluso los ingresados a sistemas de anotaciones en cuenta según el artícu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['denunciaarticulo 1876'], segments: [], amendments: [] },
  { id: 'ccyc-art-1877', lawId: 'codigo-civil-comercial', number: '1877', order: 1877, title: "Publicaciones", text: "Publicaciones. Recibida la denuncia, el juez ordena la publicación de edictos por cinco días en el Boletín Oficial y en uno de los diarios de mayor circulación en la República para citar a quienes pretenden derechos sobre los títulos valores respectivos, para que se presenten dentro de los treinta días al perito contador que se designe, para alegar y probar cuanto estimen pertinente, bajo apercibimiento de resolverse con las constancias que se agreguen a las actuaciones. Los edictos deben contener los elementos necesarios para identificar al emisor, los títulos valores a los que se refiere el registro y las demás circunstancias que el juez considere oportunas, así como las fechas para ejercer los derechos a que se refiere el artículo 1878. Si el emisor tiene establecimientos en distintas jurisdicciones judiciales, los edictos se deben publicar en cada una de ellas. Si el emisor ha sido autorizado a la oferta pública de los títulos valores a los que se refiere el registro, la denuncia debe hacerse conocer de inmediato al organismo de contralor de los mercados de valores y a las entidades expresamente autorizadas por la ley especial o la autoridad de aplicación en los que se negocien, debiéndose publicar edictos en los boletines respectivos. Si los títulos valores han sido colocados o negociados públicamente en el exterior, el juez debe ordenar las publicaciones o comunicaciones que estime apropiadas.", plainLanguageExplanation: "Establece el régimen de publicaciones. Recibida la denuncia, el juez ordena la publicación de edictos por cinco días en el Boletín Oficial y en uno de los diarios de mayor circulación en la República para citar a quienes pretenden derechos sobre los títulos valores respectivos, para que se presenten dentro de los trei", practicalEffects: ['En la práctica, este artículo rige publicaciones. Recibida la denuncia, el juez ordena la publicación de edictos por cinco días en el Boletín Oficial y en uno de los diarios de mayor circulación en la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicacionesarticulo 1877'], segments: [], amendments: [] },
  { id: 'ccyc-art-1878', lawId: 'codigo-civil-comercial', number: '1878', order: 1878, title: "Trámite", text: "Trámite. Las presentaciones se efectúan ante el perito contador designado por el juez. Se aplica el procedimiento de la verificación de créditos en los concursos, incluso en cuanto a los efectos de las resoluciones, los recursos y las presentaciones tardías. Las costas ordinarias del procedimiento son soportadas solidariamente por el emisor y por quien llevaba el libro, sin perjuicio de la repetición entre ellos.", plainLanguageExplanation: "Establece el régimen de trámite. Las presentaciones se efectúan ante el perito contador designado por el juez.", practicalEffects: ['En la práctica, este artículo rige trámite. Las presentaciones se efectúan ante el perito contador designado por el juez.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['trmitearticulo 1878'], segments: [], amendments: [] },
  { id: 'ccyc-art-1879', lawId: 'codigo-civil-comercial', number: '1879', order: 1879, title: "Nuevo libro", text: "Nuevo libro. El juez debe disponer la confección de un nuevo libro de registro, en el que se asienten las inscripciones que se ordenen por sentencia firme.", plainLanguageExplanation: "Establece el régimen de nuevo libro. El juez debe disponer la confección de un nuevo libro de registro, en el que se asienten las inscripciones que se ordenen por sentencia firme.", practicalEffects: ['En la práctica, este artículo rige nuevo libro. El juez debe disponer la confección de un nuevo libro de registro, en el que se asienten las inscripciones que se ordenen por sentencia firme.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nuevo', 'libro', 'articulo 1879'], segments: [], amendments: [] },
  { id: 'ccyc-art-1880', lawId: 'codigo-civil-comercial', number: '1880', order: 1880, title: "Ejercicio de derechos", text: "Ejercicio de derechos. El juez puede conceder a los presentantes el ejercicio cautelar de los derechos emergentes de los títulos valores antes de la confección del nuevo libro, en su caso, antes de que se dicte o quede firme la sentencia que ordena la inscripción respecto de un título valor determinado, conforme a la verosimilitud del derecho invocado y, de estimarlo necesario, bajo la caución que determine. En todos los casos, el emisor debe depositar a la orden del juez las prestaciones de contenido patrimonial que sean exigibles.", plainLanguageExplanation: "Establece el régimen de ejercicio de derechos. El juez puede conceder a los presentantes el ejercicio cautelar de los derechos emergentes de los títulos valores antes de la confección del nuevo libro, en su caso, antes de que se dicte o quede firme la sentencia que ordena la inscripción respecto de un título valor determinado", practicalEffects: ['En la práctica, este artículo rige ejercicio de derechos. El juez puede conceder a los presentantes el ejercicio cautelar de los derechos emergentes de los títulos valores antes de la confección del nuevo lib'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejercicio', 'derechos', 'articulo 1880'], segments: [], amendments: [] },
  { id: 'ccyc-art-1881', lawId: 'codigo-civil-comercial', number: '1881', order: 1881, title: "Medidas especiales", text: "Medidas especiales. La denuncia de sustracción, pérdida o destrucción del libro de registro autoriza al juez, a pedido de parte interesada y conforme a las circunstancias del caso, a disponer una intervención cautelar o una veeduría respecto del emisor y de quien llevaba el libro, con la extensión que estima pertinente para la adecuada protección de quienes resultan titulares de derechos sobre los títulos valores registrados. Puede, también, ordenar la suspensión de la realización de asambleas, cuando circunstancias excepcionales así lo aconsejen. LIBRO CUARTO DERECHOS REALES TITULO I Disposiciones generales CAPITULO 1 Principios comunes", plainLanguageExplanation: "Establece el régimen de medidas especiales. La denuncia de sustracción, pérdida o destrucción del libro de registro autoriza al juez, a pedido de parte interesada y conforme a las circunstancias del caso, a disponer una intervención cautelar o una veeduría respecto del emisor y de quien llevaba el libro, con la extensión q", practicalEffects: ['En la práctica, este artículo rige medidas especiales. La denuncia de sustracción, pérdida o destrucción del libro de registro autoriza al juez, a pedido de parte interesada y conforme a las circunstancias'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'especiales', 'articulo 1881'], segments: [], amendments: [] },
];
